/**
 * ESO (Economic Statistics Organizations) Service
 *
 * Provides real-time economic data ingestion from SEC, BLS, and Census.
 * Integrates with ValueOS for deterministic B2B value orchestration.
 */

import {
  SECAdapter,
  BLSAdapter,
  CensusAdapter,
  DataIngestionAdapter,
  IngestionConfig,
} from "./";

export interface ESODataPoint {
  source: "SEC" | "BLS" | "Census";
  data: any;
  timestamp: string;
  id: string;
}

export interface ESOConfig {
  sec: IngestionConfig;
  bls: IngestionConfig;
  census: IngestionConfig;
  enableRealtime: boolean;
}

export class ESOService {
  private adapters: Map<string, DataIngestionAdapter> = new Map();
  private dataCallbacks: Set<(data: ESODataPoint) => void> = new Set();

  constructor(private config: ESOConfig) {
    this.initializeAdapters();
    if (config.enableRealtime) {
      this.startRealtimeStreaming();
    }
  }

  private initializeAdapters() {
    this.adapters.set("SEC", new SECAdapter(this.config.sec));
    this.adapters.set("BLS", new BLSAdapter(this.config.bls));
    this.adapters.set("Census", new CensusAdapter(this.config.census));
  }

  private async startRealtimeStreaming() {
    // Start streaming for each adapter that supports it
    for (const [source, adapter] of Array.from(this.adapters)) {
      if (adapter.startStreaming) {
        try {
          // Set up data callback for this adapter
          const unsubscribe = adapter.onData?.((data: any) => {
            const dataPoint: ESODataPoint = {
              source: source as "SEC" | "BLS" | "Census",
              data,
              timestamp: new Date().toISOString(),
              id: `${source}-${Date.now()}-${Math.random().toString(36).substr(2, 9)}`,
            };
            this.notifyDataCallbacks(dataPoint);
          });

          // Start streaming with default parameters
          await adapter.startStreaming?.();
        } catch (error) {
          console.error(`Failed to start streaming for ${source}:`, error);
        }
      }
    }
  }

  /**
   * Fetch data from a specific ESO source
   */
  async fetchData(
    source: "SEC" | "BLS" | "Census",
    params?: Record<string, any>
  ): Promise<ESODataPoint> {
    const adapter = this.adapters.get(source);
    if (!adapter) {
      throw new Error(`Unknown ESO source: ${source}`);
    }

    const rawData = await adapter.fetchData(params);
    const transformedData = await adapter.transformData(rawData);

    const dataPoint: ESODataPoint = {
      source,
      data: transformedData,
      timestamp: new Date().toISOString(),
      id: `${source}-${Date.now()}-${Math.random().toString(36).substr(2, 9)}`,
    };

    this.notifyDataCallbacks(dataPoint);
    return dataPoint;
  }

  /**
   * Subscribe to real-time ESO data updates
   */
  subscribe(callback: (data: ESODataPoint) => void): () => void {
    this.dataCallbacks.add(callback);
    return () => this.dataCallbacks.delete(callback);
  }

  private notifyDataCallbacks(data: ESODataPoint) {
    this.dataCallbacks.forEach((callback) => {
      try {
        callback(data);
      } catch (error) {
        console.error("ESO data callback error:", error);
      }
    });
  }

  /**
   * Stop real-time data streaming
   */
  async stopRealtimeStreaming(): Promise<void> {
    for (const adapter of Array.from(this.adapters.values())) {
      if (adapter.stopStreaming) {
        try {
          await adapter.stopStreaming();
        } catch (error) {
          console.error("Error stopping streaming:", error);
        }
      }
    }
  }

  /**
   * Get available ESO sources
   */
  getSources(): string[] {
    return Array.from(this.adapters.keys());
  }

  /**
   * Check if real-time streaming is active
   */
  isRealtimeActive(): boolean {
    // For now, assume streaming is active if enabled
    // In a real implementation, you'd check adapter states
    return this.config.enableRealtime;
  }
}

import { DataIngestionAdapter, IngestionConfig } from "../types.js";
import { RateLimiter } from "../utils/rateLimiter.js";
import { Cache } from "../utils/cache.js";

export class BLSAdapter implements DataIngestionAdapter {
  name = "BLS";
  private rateLimiter?: RateLimiter;
  private cache?: Cache;
  private ws?: WebSocket;
  private dataCallbacks: Set<(data: any) => void> = new Set();
  private reconnectTimer?: NodeJS.Timeout;
  private isStreaming = false;
  private pollTimer?: NodeJS.Timeout;
  private lastDataTimestamps: Map<string, string> = new Map();

  constructor(private config: IngestionConfig) {
    if (config.rateLimit) {
      this.rateLimiter = new RateLimiter(config.rateLimit, 60000);
    }
    if (config.enableCache) {
      this.cache = new Cache(config.cacheTTL);
    }
  }

  async fetchData(params: {
    seriesId: string;
    startYear?: string;
    endYear?: string;
  }): Promise<any> {
    const cacheKey = `bls-${JSON.stringify(params)}`;
    if (this.cache) {
      const cached = this.cache.get(cacheKey);
      if (cached) return cached;
    }

    if (this.rateLimiter) {
      await this.rateLimiter.waitForToken();
    }

    const url = new URL(`${this.config.baseUrl}/timeseries/data/`);
    url.searchParams.set("seriesid", params.seriesId);
    if (params.startYear) url.searchParams.set("startyear", params.startYear);
    if (params.endYear) url.searchParams.set("endyear", params.endYear);
    if (this.config.apiKey) url.searchParams.set("registrationkey", this.config.apiKey);

    const response = await fetch(url.toString(), {
      headers: {
        "Content-Type": "application/json",
      },
    });

    if (!response.ok) {
      throw new Error(`BLS API error: ${response.status}`);
    }

    const data = await response.json();

    if (this.cache) {
      this.cache.set(cacheKey, data);
    }

    return data;
  }

  async transformData(rawData: any): Promise<any> {
    // Transform BLS data to standardized format
    return {
      source: "BLS",
      data: rawData,
      timestamp: new Date().toISOString(),
    };
  }

  async startStreaming(
    params: { seriesIds?: string[]; pollInterval?: number } = {}
  ): Promise<void> {
    if (this.isStreaming) return;

    this.isStreaming = true;

    // BLS data is typically released on schedules, so we use polling for "real-time"
    // In a production system, you might connect to a real-time economic data service
    const pollInterval = params.pollInterval || 300000; // 5 minutes default

    const poll = async () => {
      if (!this.isStreaming) return;

      try {
        const seriesIds = params.seriesIds || ["CES0000000001"]; // Default: Total nonfarm employment

        for (const seriesId of seriesIds) {
          const data = await this.fetchData({ seriesId });

          // Check if data has been updated
          const latestTimestamp =
            data?.Results?.series?.[0]?.data?.[0]?.year +
            data?.Results?.series?.[0]?.data?.[0]?.period;
          const lastTimestamp = this.lastDataTimestamps.get(seriesId);

          if (latestTimestamp !== lastTimestamp) {
            this.lastDataTimestamps.set(seriesId, latestTimestamp);
            this.notifyDataCallbacks(data);
          }
        }
      } catch (error) {
        console.error("BLS polling error:", error);
      }

      this.pollTimer = setTimeout(poll, pollInterval);
    };

    // Start polling immediately
    poll();
  }

  async stopStreaming(): Promise<void> {
    this.isStreaming = false;

    if (this.pollTimer) {
      clearTimeout(this.pollTimer);
      this.pollTimer = undefined;
    }

    if (this.reconnectTimer) {
      clearTimeout(this.reconnectTimer);
      this.reconnectTimer = undefined;
    }
  }

  onData(callback: (data: any) => void): () => void {
    this.dataCallbacks.add(callback);
    return () => this.dataCallbacks.delete(callback);
  }

  private notifyDataCallbacks(data: any) {
    this.dataCallbacks.forEach((callback) => {
      try {
        callback(data);
      } catch (error) {
        console.error("BLS data callback error:", error);
      }
    });
  }
}

import { DataIngestionAdapter, IngestionConfig } from "../types.js";
import { RateLimiter } from "../utils/rateLimiter.js";
import { Cache } from "../utils/cache.js";

export class CensusAdapter implements DataIngestionAdapter {
  name = "Census";
  private rateLimiter?: RateLimiter;
  private cache?: Cache;
  private dataCallbacks: Set<(data: any) => void> = new Set();
  private isStreaming = false;
  private pollTimer?: NodeJS.Timeout;
  private lastDataTimestamps: Map<string, string> = new Map();

  constructor(private config: IngestionConfig) {
    if (config.rateLimit) {
      this.rateLimiter = new RateLimiter(config.rateLimit, 60000);
    }
    if (config.enableCache) {
      this.cache = new Cache(config.cacheTTL);
    }
  }

  async fetchData(params: {
    dataset: string;
    variables: string[];
    geography?: string;
  }): Promise<any> {
    const cacheKey = `census-${JSON.stringify(params)}`;
    if (this.cache) {
      const cached = this.cache.get(cacheKey);
      if (cached) return cached;
    }

    if (this.rateLimiter) {
      await this.rateLimiter.waitForToken();
    }

    const url = new URL(`${this.config.baseUrl}/data/${params.dataset}`);
    url.searchParams.set("get", params.variables.join(","));
    if (params.geography) url.searchParams.set("for", params.geography);
    if (this.config.apiKey) url.searchParams.set("key", this.config.apiKey);

    const response = await fetch(url.toString(), {
      headers: {
        "Content-Type": "application/json",
      },
    });

    if (!response.ok) {
      throw new Error(`Census API error: ${response.status}`);
    }

    const data = await response.json();

    if (this.cache) {
      this.cache.set(cacheKey, data);
    }

    return data;
  }

  async transformData(rawData: any): Promise<any> {
    // Transform Census data to standardized format
    return {
      source: "Census",
      data: rawData,
      timestamp: new Date().toISOString(),
    };
  }

  async startStreaming(
    params: {
      datasets?: Array<{ dataset: string; variables: string[]; geography?: string }>;
      pollInterval?: number;
    } = {}
  ): Promise<void> {
    if (this.isStreaming) return;

    this.isStreaming = true;

    // Census data is released on schedules, so we use polling for "real-time"
    const pollInterval = params.pollInterval || 3600000; // 1 hour default (Census data updates less frequently)

    const poll = async () => {
      if (!this.isStreaming) return;

      try {
        const datasets = params.datasets || [
          { dataset: "acs/acs5", variables: ["B01003_001E"], geography: "state:*" }, // Default: Population by state
        ];

        for (const dataset of datasets) {
          const data = await this.fetchData(dataset);

          // Check if data has been updated (simplified check)
          const dataKey = `${dataset.dataset}-${dataset.variables.join(",")}-${dataset.geography}`;
          const currentTimestamp = new Date().toISOString();
          const lastTimestamp = this.lastDataTimestamps.get(dataKey);

          // For demo purposes, we'll emit data on each poll
          // In production, you'd check for actual data changes
          if (!lastTimestamp || Date.now() - new Date(lastTimestamp).getTime() > pollInterval) {
            this.lastDataTimestamps.set(dataKey, currentTimestamp);
            this.notifyDataCallbacks({ ...data, dataset: dataset.dataset });
          }
        }
      } catch (error) {
        console.error("Census polling error:", error);
      }

      this.pollTimer = setTimeout(poll, pollInterval);
    };

    // Start polling immediately
    poll();
  }

  async stopStreaming(): Promise<void> {
    this.isStreaming = false;

    if (this.pollTimer) {
      clearTimeout(this.pollTimer);
      this.pollTimer = undefined;
    }
  }

  onData(callback: (data: any) => void): () => void {
    this.dataCallbacks.add(callback);
    return () => this.dataCallbacks.delete(callback);
  }

  private notifyDataCallbacks(data: any) {
    this.dataCallbacks.forEach((callback) => {
      try {
        callback(data);
      } catch (error) {
        console.error("Census data callback error:", error);
      }
    });
  }
}

/**
 * @valueos/infra/eso
 *
 * ESO (Economic Statistics Organizations) data ingestion adapters.
 */

export type { DataIngestionAdapter, IngestionConfig, ESOAdapterType } from "./types.js";
export { SECAdapter } from "./sec/index.js";
export { BLSAdapter } from "./bls/index.js";
export { CensusAdapter } from "./census/index.js";
export { RateLimiter } from "./utils/rateLimiter.js";
export { Cache } from "./utils/cache.js";

import { DataIngestionAdapter, IngestionConfig } from "../types.js";
import { RateLimiter } from "../utils/rateLimiter.js";
import { Cache } from "../utils/cache.js";

export class SECAdapter implements DataIngestionAdapter {
  name = "SEC";
  private rateLimiter?: RateLimiter;
  private cache?: Cache;
  private ws?: WebSocket;
  private dataCallbacks: Set<(data: any) => void> = new Set();
  private reconnectTimer?: NodeJS.Timeout;
  private isStreaming = false;

  constructor(private config: IngestionConfig) {
    if (config.rateLimit) {
      this.rateLimiter = new RateLimiter(config.rateLimit, 60000); // per minute
    }
    if (config.enableCache) {
      this.cache = new Cache(config.cacheTTL);
    }
  }

  async fetchData(params: { cik?: string; type?: string } = {}): Promise<any> {
    const cacheKey = `sec-${JSON.stringify(params)}`;
    if (this.cache) {
      const cached = this.cache.get(cacheKey);
      if (cached) return cached;
    }

    if (this.rateLimiter) {
      await this.rateLimiter.waitForToken();
    }

    // SEC EDGAR API example
    // For company search: https://www.sec.gov/edgar/searchedgar/cik.htm
    // For filings: https://www.sec.gov/edgar/searchedgar/filings.htm

    const url = new URL(this.config.baseUrl);
    if (params.cik) {
      url.searchParams.set("cik", params.cik);
    }
    if (params.type) {
      url.searchParams.set("type", params.type);
    }

    const response = await fetch(url.toString(), {
      headers: {
        "User-Agent": "ValueOS/1.0",
      },
    });

    if (!response.ok) {
      throw new Error(`SEC API error: ${response.status}`);
    }

    const data = await response.json();

    if (this.cache) {
      this.cache.set(cacheKey, data);
    }

    return data;
  }

  async transformData(rawData: any): Promise<any> {
    // Transform SEC data to standardized format
    // This would depend on the specific endpoint
    return {
      source: "SEC",
      data: rawData,
      timestamp: new Date().toISOString(),
    };
  }

  async startStreaming(params: { symbols?: string[] } = {}): Promise<void> {
    if (this.isStreaming) return;

    // For real-time SEC data, we might connect to a financial data WebSocket
    // This is a placeholder - in reality, you'd connect to a service like Alpha Vantage, IEX, etc.
    const wsUrl = this.config.baseUrl.replace("https", "wss") + "/stream";

    this.ws = new WebSocket(wsUrl);

    this.ws.onopen = () => {
      console.log("SEC WebSocket connected");
      this.isStreaming = true;

      // Subscribe to specific symbols or general market data
      const subscription = {
        type: "subscribe",
        symbols: params.symbols || ["market-overview"],
        source: "SEC",
      };
      this.ws?.send(JSON.stringify(subscription));
    };

    this.ws.onmessage = (event) => {
      try {
        const data = JSON.parse(event.data);
        this.notifyDataCallbacks(data);
      } catch (error) {
        console.error("Failed to parse SEC WebSocket data:", error);
      }
    };

    this.ws.onclose = () => {
      console.log("SEC WebSocket disconnected");
      this.isStreaming = false;
      this.scheduleReconnect();
    };

    this.ws.onerror = (error) => {
      console.error("SEC WebSocket error:", error);
    };
  }

  async stopStreaming(): Promise<void> {
    if (this.reconnectTimer) {
      clearTimeout(this.reconnectTimer);
      this.reconnectTimer = undefined;
    }

    if (this.ws) {
      this.ws.close();
      this.ws = undefined;
    }
    this.isStreaming = false;
  }

  onData(callback: (data: any) => void): () => void {
    this.dataCallbacks.add(callback);
    return () => this.dataCallbacks.delete(callback);
  }

  private notifyDataCallbacks(data: any) {
    this.dataCallbacks.forEach((callback) => {
      try {
        callback(data);
      } catch (error) {
        console.error("SEC data callback error:", error);
      }
    });
  }

  private scheduleReconnect() {
    if (this.reconnectTimer) return;

    this.reconnectTimer = setTimeout(() => {
      console.log("Attempting to reconnect SEC WebSocket...");
      this.startStreaming();
    }, 5000); // Reconnect after 5 seconds
  }
}

/**
 * @valueos/infra/eso
 *
 * ESO (Economic Statistics Organizations) data ingestion adapters.
 * - SEC: Securities and Exchange Commission
 * - BLS: Bureau of Labor Statistics
 * - Census: US Census Bureau
 */

export interface DataIngestionAdapter {
  name: string;
  fetchData(params?: Record<string, any>): Promise<any>;
  transformData(rawData: any): Promise<any>;
  // Real-time streaming support
  startStreaming?(params?: Record<string, any>): Promise<void>;
  stopStreaming?(): Promise<void>;
  onData?(callback: (data: any) => void): () => void;
}

export interface IngestionConfig {
  apiKey?: string;
  baseUrl: string;
  rateLimit?: number; // requests per minute
  timeout?: number;
  enableCache?: boolean;
  cacheTTL?: number; // in milliseconds
}

export type ESOAdapterType = "sec" | "bls" | "census";

/**
 * Simple in-memory cache with TTL
 */
export class Cache {
  private cache = new Map<string, { data: any; expiry: number }>();

  constructor(private defaultTTL: number = 300000) {} // 5 minutes default

  get(key: string): any | null {
    const entry = this.cache.get(key);
    if (!entry) return null;

    if (Date.now() > entry.expiry) {
      this.cache.delete(key);
      return null;
    }

    return entry.data;
  }

  set(key: string, data: any, ttl?: number): void {
    const expiry = Date.now() + (ttl || this.defaultTTL);
    this.cache.set(key, { data, expiry });
  }

  clear(): void {
    this.cache.clear();
  }

  size(): number {
    // Clean expired entries
    for (const [key, entry] of Array.from(this.cache)) {
      if (Date.now() > entry.expiry) {
        this.cache.delete(key);
      }
    }
    return this.cache.size;
  }
}

/**
 * Simple rate limiter using token bucket algorithm
 */
export class RateLimiter {
  private tokens: number;
  private lastRefill: number;
  private readonly maxTokens: number;
  private readonly refillRate: number; // tokens per second

  constructor(maxRequests: number, windowMs: number) {
    this.maxTokens = maxRequests;
    this.tokens = maxRequests;
    this.lastRefill = Date.now();
    this.refillRate = maxRequests / (windowMs / 1000);
  }

  async waitForToken(): Promise<void> {
    this.refill();

    if (this.tokens >= 1) {
      this.tokens -= 1;
      return;
    }

    // Wait for next token
    const waitTime = ((1 - this.tokens) / this.refillRate) * 1000;
    await new Promise((resolve) => setTimeout(resolve, waitTime));
    this.tokens -= 1;
  }

  private refill(): void {
    const now = Date.now();
    const timePassed = (now - this.lastRefill) / 1000;
    const tokensToAdd = timePassed * this.refillRate;

    this.tokens = Math.min(this.maxTokens, this.tokens + tokensToAdd);
    this.lastRefill = now;
  }
}

/**
 * Request Context Storage
 *
 * Uses AsyncLocalStorage to maintain request-scoped context (requestId, tenantId, etc.)
 * across the call stack.
 */

export interface RequestContext {
  requestId?: string;
  tenantId?: string;
  userId?: string;
  traceId?: string;
  spanId?: string;
  [key: string]: unknown;
}

let storage: any = null;

/**
 * Initialize the context storage (Node.js only)
 */
export async function initializeContext(): Promise<void> {
  if (typeof window === 'undefined') {
    try {
      const { AsyncLocalStorage } = await import('async_hooks');
      storage = new AsyncLocalStorage<RequestContext>();
    } catch (err) {
       // We can't log here because of circular dependency with logger
       // console.warn('Failed to initialize AsyncLocalStorage', err);
    }
  }
}

/**
 * Run a function within a context
 */
export function runWithContext<T>(context: RequestContext, fn: () => T): T {
  if (storage) {
    return storage.run(context, fn);
  }
  return fn();
}

/**
 * Get the current context
 */
export function getContext(): RequestContext | undefined {
  if (storage) {
    return storage.getStore();
  }
  return undefined;
}

/**
 * Database connection utilities for ValueOS
 * Handles environment-specific database host and port detection
 */

/**
 * Get database host deterministically based on environment
 * - Local Supabase CLI: localhost
 * - Docker: db (internal service name)
 * - Production: environment variable
 */
export function get_db_host(): string {
  // Check if running in Docker environment
  if (process.env.DOCKER_CONTAINER === "true" || process.env.COMPOSE_PROJECT_NAME) {
    return process.env.DB_HOST || "db";
  }

  // Supabase CLI local development
  if (process.env.SUPABASE_LOCAL === "true") {
    return "localhost";
  }

  // Production or explicit host
  return process.env.DB_HOST || "localhost";
}

/**
 * Get database port deterministically
 */
export function get_db_port(): number {
  if (process.env.SUPABASE_LOCAL === "true") {
    return 54322; // From supabase/config.toml
  }

  return parseInt(process.env.DB_PORT || "5432", 10);
}

/**
 * Get full database URL for direct connections
 */
export function get_database_url(): string {
  const host = get_db_host();
  const port = get_db_port();
  const user = process.env.DB_USER || "postgres";
  const password = process.env.DB_PASSWORD || "postgres";
  const database = process.env.DB_NAME || "postgres";

  return `postgresql://${user}:${password}@${host}:${port}/${database}`;
}

/**
 * Environment Variable Utilities
 * Browser-safe implementation that avoids process references
 */

// Check once at module load time
const _isBrowser = typeof window !== "undefined";

export const REQUIRED_ENV_VARS = [
  "VITE_SUPABASE_URL",
  "VITE_SUPABASE_ANON_KEY",
  "SUPABASE_SERVICE_ROLE_KEY",
  "DATABASE_URL",
] as const;

export function validateRequiredEnv(): void {
  // Skip validation in browser (validation is server-side)
  if (_isBrowser) return;

  // Server-side validation (self-contained, no cross-package imports)
  const missing: string[] = [];
  for (const key of REQUIRED_ENV_VARS) {
    if (typeof process !== "undefined" && process.env && !process.env[key]) {
      missing.push(key);
    }
  }
  if (missing.length > 0) {
    console.warn(`[env] Missing environment variables: ${missing.join(", ")}`);
  }
}

export function validateEnv() {
  validateRequiredEnv();
}

// Helper function to safely access environment variables
function getEnvValue(key: string): string | undefined {
  if (_isBrowser) {
    // In browser environments, use import.meta.env if available (Vite)
    return (import.meta as any)?.env?.[key];
  } else {
    // In Node.js environments, use process.env
    return typeof process !== "undefined" && process.env ? process.env[key] : undefined;
  }
}

export const env = {
  isDevelopment: _isBrowser ? getEnvValue("DEV") === "true" : false,
  isProduction: _isBrowser ? getEnvValue("PROD") === "true" : false,
  isTest: false,
  isBrowser: _isBrowser,
  isServer: !_isBrowser,
};

export interface GetEnvVarOptions {
  required?: boolean;
  defaultValue?: string;
  scope?: "browser" | "server";
}

export function getEnvVar(key: string, options: GetEnvVarOptions = {}): string | undefined {
  const { required = false, defaultValue, scope } = options;

  let value: string | undefined = getEnvValue(key);

  if (!value && defaultValue) {
    value = defaultValue;
  }

  if (!value && required) {
    const errorScope = scope || (_isBrowser ? "browser" : "server");
    throw new Error(`Missing required ${errorScope} environment variable: ${key}`);
  }

  return value;
}

export function setEnvVar(key: string, value: string): void {
  if (_isBrowser) {
    if ((import.meta as any)?.env) {
      (import.meta as any).env[key] = value;
    }
  } else {
    if (typeof process !== "undefined" && process.env) {
      process.env[key] = value;
    }
  }
}

export function checkIsBrowser(): boolean {
  return _isBrowser;
}

export function __setEnvSourceForTests(envSource: Record<string, string>): void {
  if (_isBrowser) {
    if ((import.meta as any)?.env) {
      Object.assign((import.meta as any).env, envSource);
    }
  } else {
    if (typeof process !== "undefined" && process.env) {
      Object.assign(process.env, envSource);
    }
  }
}

export function getSupabaseConfig(): {
  url: string;
  anonKey: string;
  serviceRoleKey?: string;
} {
  const serviceRoleKey =
    getEnvVar("SUPABASE_SERVICE_ROLE_KEY") || getEnvVar("SUPABASE_SERVICE_KEY");
