/**
 * @valueos/shared Feature Flags
 *
 * Shared feature flag definitions and parsing utilities.
 * This is the single source of truth for feature flag types and defaults.
 *
 * Usage:
 *   import { FeatureFlags, parseBoolean, getSecurityFlagDefaults } from '@valueos/shared';
 */

/**
 * Feature flag configuration interface
 */
export interface FeatureFlags {
  // Orchestration
  ENABLE_UNIFIED_ORCHESTRATION: boolean;
  /** @deprecated Use ENABLE_UNIFIED_ORCHESTRATION instead */
  ENABLE_STATELESS_ORCHESTRATION: boolean;

  // Security
  ENABLE_SAFE_JSON_PARSER: boolean;
  ENABLE_INPUT_SANITIZATION: boolean;
  ENABLE_CIRCUIT_BREAKER: boolean;
  ENABLE_RATE_LIMITING: boolean;
  ENABLE_AUDIT_LOGGING: boolean;

  // Observability
  ENABLE_TRACE_LOGGING: boolean;

  // Async execution
  ENABLE_ASYNC_AGENT_EXECUTION: boolean;

  // Legacy
  DISABLE_LEGACY_BUSINESS_CASES: boolean;

  // Sprint 0: Security flags
  ENABLE_VALUE_COMMITMENT_SERVICE: boolean;
  ENABLE_AGENT_PLACEHOLDER_MODE: boolean;
  ENABLE_CLIENT_LLM_STREAMING: boolean;
}

/**
 * Parse boolean from environment variable
 */
export function parseBoolean(value: string | undefined, defaultValue: boolean = false): boolean {
  if (value === undefined) return defaultValue;
  return value.toLowerCase() === "true" || value === "1";
}

/**
 * Get security-safe defaults for production
 * Sprint 0: These MUST be false in production
 */
export function getSecurityFlagDefaults(isProduction: boolean): Partial<FeatureFlags> {
  return {
    ENABLE_VALUE_COMMITMENT_SERVICE: false, // Always false until fully implemented
    ENABLE_AGENT_PLACEHOLDER_MODE: !isProduction,
    ENABLE_CLIENT_LLM_STREAMING: !isProduction,
  };
}

/**
 * Get full defaults for all flags
 */
export function getDefaultFlags(isProduction: boolean): FeatureFlags {
  const securityDefaults = getSecurityFlagDefaults(isProduction);
  return {
    // Orchestration - enabled by default
    ENABLE_UNIFIED_ORCHESTRATION: true,
    ENABLE_STATELESS_ORCHESTRATION: false, // deprecated

    // Security - enabled by default
    ENABLE_SAFE_JSON_PARSER: true,
    ENABLE_INPUT_SANITIZATION: true,
    ENABLE_CIRCUIT_BREAKER: true,
    ENABLE_RATE_LIMITING: true,
    ENABLE_AUDIT_LOGGING: true,

    // Observability - enabled by default
    ENABLE_TRACE_LOGGING: true,

    // Async - gradual rollout
    ENABLE_ASYNC_AGENT_EXECUTION: false,

    // Legacy - maintain backward compatibility
    DISABLE_LEGACY_BUSINESS_CASES: false,

    // Sprint 0: Security flags with safe defaults
    ENABLE_VALUE_COMMITMENT_SERVICE: securityDefaults.ENABLE_VALUE_COMMITMENT_SERVICE ?? false,
    ENABLE_AGENT_PLACEHOLDER_MODE: securityDefaults.ENABLE_AGENT_PLACEHOLDER_MODE ?? false,
    ENABLE_CLIENT_LLM_STREAMING: securityDefaults.ENABLE_CLIENT_LLM_STREAMING ?? false,
  };
}

/**
 * Rollout percentage for gradual feature enablement
 *
 * Usage:
 *   if (shouldEnableForUser(userId, 10)) { // 10% rollout
 *     // Use new feature
 *   }
 */
export function shouldEnableForUser(userId: string, percentage: number): boolean {
  if (percentage >= 100) return true;
  if (percentage <= 0) return false;

  // Deterministic hash-based rollout
  const hash = simpleHash(userId);
  return hash % 100 < percentage;
}

/**
 * Simple hash function for deterministic rollout
 */
function simpleHash(str: string): number {
  let hash = 0;
  for (let i = 0; i < str.length; i++) {
    const char = str.charCodeAt(i);
    hash = (hash << 5) - hash + char;
    hash = hash & hash; // Convert to 32-bit integer
  }
  return Math.abs(hash);
}

/**
 * Health check alert manager
 * Tracks persistent failures and manages alert states
 */

export enum AlertSeverity {
  WARNING = "warning",
  CRITICAL = "critical",
}

export enum AlertState {
  OK = "ok",
  ALERTING = "alerting",
  RESOLVED = "resolved",
}

export interface Alert {
  id: string;
  service: string;
  severity: AlertSeverity;
  state: AlertState;
  message: string;
  startedAt: number;
  resolvedAt?: number;
  lastTriggered: number;
  triggerCount: number;
}

export interface AlertRule {
  service: string;
  name: string;
  description: string;
  severity: AlertSeverity;
  condition: (stats: any) => boolean;
  cooldownMs: number; // Minimum time between alerts
}

class AlertManager {
  private alerts: Map<string, Alert> = new Map();
  private rules: AlertRule[] = [];

  constructor() {
    this.initializeDefaultRules();
  }

  private initializeDefaultRules(): void {
    // High failure rate alert
    this.addRule({
      service: "*",
      name: "high_failure_rate",
      description: "Service has high failure rate (>20%)",
      severity: AlertSeverity.WARNING,
      condition: (stats) => stats.total >= 10 && stats.successRate < 0.8,
      cooldownMs: 300000, // 5 minutes
    });

    // Critical failure alert
    this.addRule({
      service: "*",
      name: "critical_failure",
      description: "Service has critical failure rate (>50%)",
      severity: AlertSeverity.CRITICAL,
      condition: (stats) => stats.total >= 5 && stats.successRate < 0.5,
      cooldownMs: 60000, // 1 minute
    });

    // High latency alert
    this.addRule({
      service: "*",
      name: "high_latency",
      description: "Service has high P95 latency (>2000ms)",
      severity: AlertSeverity.WARNING,
      condition: (stats) => stats.p95Latency > 2000,
      cooldownMs: 300000, // 5 minutes
    });
  }

  addRule(rule: AlertRule): void {
    this.rules.push(rule);
  }

  evaluateRules(serviceStats: Record<string, any>): Alert[] {
    const newAlerts: Alert[] = [];
    const now = Date.now();

    for (const [service, stats] of Object.entries(serviceStats)) {
      for (const rule of this.rules) {
        if (rule.service !== "*" && rule.service !== service) {
          continue;
        }

        const alertId = `${service}:${rule.name}`;
        const existingAlert = this.alerts.get(alertId);

        if (rule.condition(stats)) {
          // Condition met - should alert
          if (!existingAlert || existingAlert.state === AlertState.RESOLVED) {
            // New alert or resolved alert triggering again
            const alert: Alert = {
              id: alertId,
              service,
              severity: rule.severity,
              state: AlertState.ALERTING,
              message: `${rule.description} for ${service}`,
              startedAt: now,
              lastTriggered: now,
              triggerCount: 1,
            };
            this.alerts.set(alertId, alert);
            newAlerts.push(alert);
          } else if (existingAlert.state === AlertState.ALERTING) {
            // Existing alert - update trigger count if cooldown passed
            if (now - existingAlert.lastTriggered >= rule.cooldownMs) {
              existingAlert.lastTriggered = now;
              existingAlert.triggerCount++;
              newAlerts.push(existingAlert);
            }
          }
        } else {
          // Condition not met
          if (existingAlert && existingAlert.state === AlertState.ALERTING) {
            // Resolve existing alert
            existingAlert.state = AlertState.RESOLVED;
            existingAlert.resolvedAt = now;
          }
        }
      }
    }

    return newAlerts;
  }

  getActiveAlerts(): Alert[] {
    return Array.from(this.alerts.values()).filter(
      (alert) => alert.state === AlertState.ALERTING
    );
  }

  getAllAlerts(): Alert[] {
    return Array.from(this.alerts.values());
  }

  acknowledgeAlert(alertId: string): boolean {
    const alert = this.alerts.get(alertId);
    if (alert) {
      alert.state = AlertState.RESOLVED;
      alert.resolvedAt = Date.now();
      return true;
    }
    return false;
  }
}

// Global alert manager
export const alertManager = new AlertManager();

