/**
 * Shared health check utilities
 * Common functions for health validation across different contexts
 */

import https from "https";
import http from "http";
import net from "net";
import { execSync } from "child_process";

export interface HealthCheckResult {
  healthy: boolean;
  message: string;
  latency?: number;
}

/**
 * Circuit breaker states
 */
enum CircuitState {
  CLOSED = "closed", // Normal operation
  OPEN = "open", // Failing, skip checks
  HALF_OPEN = "half_open", // Testing recovery
}

/**
 * Circuit breaker for health checks
 */
class CircuitBreaker {
  private state: CircuitState = CircuitState.CLOSED;
  private failureCount = 0;
  private lastFailureTime = 0;
  private nextAttemptTime = 0;

  constructor(
    private readonly failureThreshold: number = 5,
    private readonly recoveryTimeout: number = 60000, // 1 minute
    private readonly monitoringPeriod: number = 300000 // 5 minutes
  ) {}

  async execute<T>(operation: () => Promise<T>): Promise<T | null> {
    const now = Date.now();

    // Reset failure count if monitoring period has passed
    if (now - this.lastFailureTime > this.monitoringPeriod) {
      this.failureCount = 0;
      this.state = CircuitState.CLOSED;
    }

    // Check if circuit is open
    if (this.state === CircuitState.OPEN) {
      if (now < this.nextAttemptTime) {
        return null; // Skip the operation
      }
      // Time to try again
      this.state = CircuitState.HALF_OPEN;
    }

    try {
      const result = await operation();

      // Success - reset circuit
      this.failureCount = 0;
      this.state = CircuitState.CLOSED;

      return result;
    } catch (error) {
      this.failureCount++;
      this.lastFailureTime = now;

      if (this.failureCount >= this.failureThreshold) {
        this.state = CircuitState.OPEN;
        this.nextAttemptTime = now + this.recoveryTimeout;
      } else if (this.state === CircuitState.HALF_OPEN) {
        // Failed during recovery attempt
        this.state = CircuitState.OPEN;
        this.nextAttemptTime = now + this.recoveryTimeout;
      }

      throw error;
    }
  }

  getState(): CircuitState {
    return this.state;
  }

  getFailureCount(): number {
    return this.failureCount;
  }

  getLastFailureTime(): number {
    return this.lastFailureTime;
  }

  getNextAttemptTime(): number {
    return this.nextAttemptTime;
  }

  reset(): void {
    this.failureCount = 0;
    this.state = CircuitState.CLOSED;
    this.lastFailureTime = 0;
    this.nextAttemptTime = 0;
  }

  recordFailure(): void {
    this.failureCount++;
    this.lastFailureTime = Date.now();

    if (this.failureCount >= this.failureThreshold) {
      this.state = CircuitState.OPEN;
      this.nextAttemptTime = Date.now() + this.recoveryTimeout;
    }
  }
}

// Global circuit breakers for different services
const circuitBreakers = new Map<string, CircuitBreaker>();

/**
 * Get or create circuit breaker for a service
 */
function getCircuitBreaker(serviceName: string): CircuitBreaker {
  if (!circuitBreakers.has(serviceName)) {
    circuitBreakers.set(serviceName, new CircuitBreaker());
  }
  return circuitBreakers.get(serviceName)!;
}

/**
 * Check HTTP/HTTPS endpoint with circuit breaker
 */
export async function checkHttpEndpoint(
  url: string,
  timeout: number = 5000
): Promise<HealthCheckResult> {
  const circuitBreaker = getCircuitBreaker(`http:${url}`);

  try {
    const result = await circuitBreaker.execute(async () => {
      const startTime = Date.now();

      return new Promise<HealthCheckResult>((resolve) => {
        const client = url.startsWith("https:") ? https : http;
        const req = client.get(url, { timeout }, (res) => {
          const responseTime = Date.now() - startTime;
          const isHealthy = Boolean(
            res.statusCode && res.statusCode >= 200 && res.statusCode < 300
          );

          res.on("data", () => {}); // Consume response
          res.on("end", () => {
            resolve({
              healthy: isHealthy,
              message: isHealthy
                ? `HTTP ${res.statusCode} (${responseTime}ms)`
                : `HTTP ${res.statusCode}`,
              latency: responseTime,
            });
          });
        });

        req.on("error", (err: NodeJS.ErrnoException) => {
          resolve({
            healthy: false,
            message: err.code || err.message || "Connection error",
            latency: Date.now() - startTime,
          });
        });

        req.on("timeout", () => {
          req.destroy();
          resolve({
            healthy: false,
            message: "timeout",
            latency: Date.now() - startTime,
          });
        });
      });
    });

    // Handle null result from circuit breaker (circuit is open)
    if (result === null) {
      return {
        healthy: false,
        message: "Circuit breaker open - service temporarily unavailable",
      };
    }

    return result;
  } catch {
    return {
      healthy: false,
      message: "Circuit breaker open - service temporarily unavailable",
    };
  }
}

/**
 * Check if a Docker service is running with circuit breaker
 */
export function checkDockerService(serviceName: string, projectRoot: string): HealthCheckResult {
  const circuitBreaker = getCircuitBreaker(`docker:${serviceName}`);

  try {
    // For synchronous operations, we need to check circuit breaker state manually
    const now = Date.now();

    // Reset failure count if monitoring period has passed
    const lastFailure = circuitBreaker.getLastFailureTime();
    if (now - lastFailure > 300000) {
      // 5 minutes
      circuitBreaker.reset();
    }

    // Check if circuit is open
    if (circuitBreaker.getState() === "open") {
      const nextAttempt = circuitBreaker.getNextAttemptTime();
      if (now < nextAttempt) {
        return {
          healthy: false,
          message: "Circuit breaker open - service temporarily unavailable",
        };
      }
    }

    const output = execSync(`docker compose ps ${serviceName}`, {
      cwd: projectRoot,
      encoding: "utf8",
      timeout: 10000,
    });

    const isRunning = output.includes(serviceName) && !output.includes("Exit");

    // Success - reset circuit breaker
    circuitBreaker.reset();

    return {
      healthy: isRunning,
      message: isRunning ? "running" : "not running",
    };
  } catch (error) {
    // Record failure in circuit breaker
    circuitBreaker.recordFailure();

    return {
      healthy: false,
      message: "Circuit breaker open - service temporarily unavailable",
    };
  }
}

/**
 * Check if a port is in use
 */
export async function isPortInUse(port: number, host: string = "127.0.0.1"): Promise<boolean> {
  return new Promise((resolve) => {
    const tester = net
      .createServer()
      .once("error", (error: NodeJS.ErrnoException) => {
        resolve(error.code === "EADDRINUSE");
      })
      .once("listening", () => {
        tester.close(() => resolve(false));
      })
      .listen(port, host);
  });
}

/**
 * Check if a command exists in PATH
 */
export function commandExists(command: string): boolean {
  try {
    execSync(`command -v ${command}`, { stdio: "ignore" });
    return true;
  } catch {
    return false;
  }
}

/**
 * Run a command and return its output
 */
export function runCommand(
  command: string,
  options: { cwd?: string; timeout?: number } = {}
): string {
  return execSync(command, {
    cwd: options.cwd,
    stdio: "pipe",
    encoding: "utf8",
    timeout: options.timeout,
    ...options,
  });
}

/**
 * Health check metrics collector
 * Tracks latency and failure rates for health checks
 */

import type { HealthCheckResult } from "./checkUtils";

interface HealthCheckMetric {
  service: string;
  timestamp: number;
  latency: number;
  success: boolean;
  error?: string;
}

interface HealthStatusSnapshot {
  timestamp: number;
  overallStatus: "healthy" | "degraded" | "unhealthy";
  checks: Record<
    string,
    {
      status: "healthy" | "degraded" | "unhealthy" | "not_configured";
      latency?: number;
      message?: string;
    }
  >;
}

class HealthMetricsCollector {
  private metrics: HealthCheckMetric[] = [];
  private healthHistory: HealthStatusSnapshot[] = [];
  private readonly maxMetrics = 1000; // Keep last 1000 metrics
  private readonly maxHistory = 100; // Keep last 100 health snapshots

  recordMetric(service: string, latency: number, success: boolean, error?: string): void {
    const metric: HealthCheckMetric = {
      service,
      timestamp: Date.now(),
      latency,
      success,
      error,
    };

    this.metrics.push(metric);

    // Keep only recent metrics
    if (this.metrics.length > this.maxMetrics) {
      this.metrics = this.metrics.slice(-this.maxMetrics);
    }
  }

  recordHealthSnapshot(
    overallStatus: "healthy" | "degraded" | "unhealthy",
    checks: Record<string, any>
  ): void {
    const snapshot: HealthStatusSnapshot = {
      timestamp: Date.now(),
      overallStatus,
      checks: { ...checks },
    };

    this.healthHistory.push(snapshot);

    // Keep only recent snapshots
    if (this.healthHistory.length > this.maxHistory) {
      this.healthHistory = this.healthHistory.slice(-this.maxHistory);
    }
  }

  getHealthHistory(timeWindowMs: number = 86400000): HealthStatusSnapshot[] {
    // Default 24 hours
    const cutoff = Date.now() - timeWindowMs;
    return this.healthHistory.filter((snapshot) => snapshot.timestamp >= cutoff);
  }

  getHealthTrends(timeWindowMs: number = 3600000): {
    overall: {
      healthy: number;
      degraded: number;
      unhealthy: number;
      total: number;
    };
    services: Record<
      string,
      {
        healthy: number;
        degraded: number;
        unhealthy: number;
        notConfigured: number;
        total: number;
      }
    >;
  } {
    const history = this.getHealthHistory(timeWindowMs);

    const overall = {
      healthy: 0,
      degraded: 0,
      unhealthy: 0,
      total: history.length,
    };

    const services: Record<string, any> = {};

    for (const snapshot of history) {
      // Count overall status
      overall[snapshot.overallStatus]++;

      // Count service statuses
      for (const [service, check] of Object.entries(snapshot.checks)) {
        if (!services[service]) {
          services[service] = {
            healthy: 0,
            degraded: 0,
            unhealthy: 0,
            notConfigured: 0,
            total: 0,
          };
        }

        services[service][check.status]++;
        services[service].total++;
      }
    }

    return { overall, services };
  }

  getMetrics(service?: string, timeWindowMs: number = 3600000): HealthCheckMetric[] {
    // Default 1 hour
    const cutoff = Date.now() - timeWindowMs;
    return this.metrics
      .filter((m) => m.timestamp >= cutoff)
      .filter((m) => !service || m.service === service);
  }

  getStats(service?: string, timeWindowMs: number = 3600000) {
    const relevantMetrics = this.getMetrics(service, timeWindowMs);

    if (relevantMetrics.length === 0) {
      return {
        total: 0,
        successful: 0,
        failed: 0,
        successRate: 0,
        avgLatency: 0,
        p95Latency: 0,
        p99Latency: 0,
      };
    }

    const successful = relevantMetrics.filter((m) => m.success);
    const failed = relevantMetrics.filter((m) => !m.success);

    const latencies = relevantMetrics.map((m) => m.latency).sort((a, b) => a - b);
    const avgLatency = latencies.reduce((sum, lat) => sum + lat, 0) / latencies.length;

    const p95Index = Math.floor(latencies.length * 0.95);
    const p99Index = Math.floor(latencies.length * 0.99);

    return {
      total: relevantMetrics.length,
      successful: successful.length,
      failed: failed.length,
      successRate: successful.length / relevantMetrics.length,
      avgLatency,
      p95Latency: latencies[p95Index] || 0,
      p99Latency: latencies[p99Index] || 0,
    };
  }

  getServiceStats(timeWindowMs: number = 3600000): Record<string, any> {
    const services = [...new Set(this.metrics.map((m) => m.service))];
    const stats: Record<string, any> = {};

    for (const service of services) {
      stats[service] = this.getStats(service, timeWindowMs);
    }

    return stats;
  }
}

// Global metrics collector
export const healthMetrics = new HealthMetricsCollector();

/**
 * Enhanced health check result with metrics tracking
 */
export interface EnhancedHealthCheckResult {
  healthy: boolean;
  message: string;
  latency?: number;
  service: string;
}

/**
 * Wrapper to track metrics for health check functions
 */
export function withMetrics<
  T extends any[],
  R extends Promise<HealthCheckResult> | HealthCheckResult,
>(service: string, fn: (...args: T) => R): (...args: T) => R {
  return (...args: T): R => {
    const startTime = Date.now();

    try {
      const result = fn(...args);

      if (result instanceof Promise) {
        return result
          .then((res: HealthCheckResult) => {
            const latency = Date.now() - startTime;
            healthMetrics.recordMetric(service, latency, res.healthy);
            return res;
          })
          .catch((error: Error) => {
            const latency = Date.now() - startTime;
            healthMetrics.recordMetric(service, latency, false, error.message);
            throw error;
          }) as R;
      } else {
        const latency = Date.now() - startTime;
        healthMetrics.recordMetric(service, latency, result.healthy);
        return result;
      }
    } catch (error) {
      const latency = Date.now() - startTime;
      healthMetrics.recordMetric(
        service,
        latency,
        false,
        error instanceof Error ? error.message : "Unknown error"
      );
      throw error;
    }
  };
}

/**
 * ID Generation Utilities
 *
 * Centralized ID generation with type-safe prefixes.
 * Provides consistent, collision-resistant identifiers across all packages.
 *
 * @example
 * const userId = ids.user();        // "usr_V1StGXR8_Z5jdHi6B-myT"
 * const taskId = ids.task();        // "tsk_1HGVzYLjR9cM2sKlEqPn4"
 * const customId = ids.prefixed('custom'); // "custom_abc123..."
 */

/**
 * Alphabet for nanoid-style generation (URL-safe)
 */
const ALPHABET = '0123456789ABCDEFGHIJKLMNOPQRSTUVWXYZabcdefghijklmnopqrstuvwxyz-_';
const DEFAULT_LENGTH = 21;

/**
 * Generate a random string of specified length
 * Uses crypto.getRandomValues for secure randomness
 */
function nanoid(length: number = DEFAULT_LENGTH): string {
  const bytes = new Uint8Array(length);
  crypto.getRandomValues(bytes);
  let id = '';
  for (let i = 0; i < length; i++) {
    id += ALPHABET[bytes[i]! & 63];
  }
  return id;
}

/**
 * ID prefix types for type-safe IDs
 */
export type IdPrefix =
  | 'usr'   // User
  | 'ten'   // Tenant
  | 'agt'   // Agent
  | 'tsk'   // Task
  | 'mem'   // Memory
  | 'ses'   // Session
  | 'msg'   // Message
  | 'evt'   // Event
  | 'tok'   // Token
  | 'key'   // API Key
  | 'wf'    // Workflow
  | 'job'   // Job
  | 'req';  // Request

/**
 * Branded type for prefixed IDs
 */
export type PrefixedId<P extends string> = `${P}_${string}`;

/**
 * Specific ID types for domain entities
 */
export type UserId = PrefixedId<'usr'>;
export type TenantId = PrefixedId<'ten'>;
export type AgentId = PrefixedId<'agt'>;
export type TaskId = PrefixedId<'tsk'>;
export type MemoryId = PrefixedId<'mem'>;
export type SessionId = PrefixedId<'ses'>;
export type MessageId = PrefixedId<'msg'>;
export type EventId = PrefixedId<'evt'>;
export type TokenId = PrefixedId<'tok'>;
export type ApiKeyId = PrefixedId<'key'>;
export type WorkflowId = PrefixedId<'wf'>;
export type JobId = PrefixedId<'job'>;
export type RequestId = PrefixedId<'req'>;

/**
 * ID generation utilities
 */
export const ids = {
  /**
   * Generate a UUID v4
   */
  uuid(): string {
    return crypto.randomUUID();
  },

  /**
   * Generate a nanoid (URL-safe, collision-resistant)
   */
  nanoid(length: number = DEFAULT_LENGTH): string {
    return nanoid(length);
  },

  /**
   * Generate a prefixed ID
   */
  prefixed<P extends string>(prefix: P, length: number = DEFAULT_LENGTH): PrefixedId<P> {
    return `${prefix}_${nanoid(length)}` as PrefixedId<P>;
  },

  /**
   * Domain-specific ID generators
   */
  user(): UserId {
    return ids.prefixed('usr');
  },

  tenant(): TenantId {
    return ids.prefixed('ten');
  },

  agent(): AgentId {
    return ids.prefixed('agt');
  },

  task(): TaskId {
    return ids.prefixed('tsk');
  },

  memory(): MemoryId {
    return ids.prefixed('mem');
  },

  session(): SessionId {
    return ids.prefixed('ses');
  },

  message(): MessageId {
    return ids.prefixed('msg');
  },

  event(): EventId {
    return ids.prefixed('evt');
  },

  token(): TokenId {
    return ids.prefixed('tok');
  },

  apiKey(): ApiKeyId {
    return ids.prefixed('key');
  },

  workflow(): WorkflowId {
    return ids.prefixed('wf');
  },

  job(): JobId {
    return ids.prefixed('job');
  },

  request(): RequestId {
    return ids.prefixed('req');
  },
};

/**
 * Parse a prefixed ID to extract prefix and value
 */
export function parseId<P extends string>(
  id: PrefixedId<P>
): { prefix: P; value: string } | null {
  const match = id.match(/^([a-z]+)_(.+)$/) as [string, P, string] | null;
  if (!match) return null;
  return { prefix: match[1] as P, value: match[2] };
}

/**
 * Validate that a string is a valid prefixed ID with expected prefix
 */
export function isValidId<P extends string>(
  id: string,
  expectedPrefix: P
): id is PrefixedId<P> {
  return id.startsWith(`${expectedPrefix}_`) && id.length > expectedPrefix.length + 1;
}

/**
 * Type guards for specific ID types
 */
export const isUserId = (id: string): id is UserId => isValidId(id, 'usr');
export const isTenantId = (id: string): id is TenantId => isValidId(id, 'ten');
export const isAgentId = (id: string): id is AgentId => isValidId(id, 'agt');
export const isTaskId = (id: string): id is TaskId => isValidId(id, 'tsk');
export const isMemoryId = (id: string): id is MemoryId => isValidId(id, 'mem');
export const isSessionId = (id: string): id is SessionId => isValidId(id, 'ses');

