    PERMISSIONS.AGENTS_EXECUTE,
  ],

  [AGENT_ROLES.OBSERVER]: [
    PERMISSIONS.VALUE_TREES_VIEW,
    PERMISSIONS.COMMITMENTS_VIEW,
    PERMISSIONS.AGENTS_VIEW,
  ],
};

export const LEGACY_ROLE_MAP: Record<string, UserRole> = {
  owner: USER_ROLES.ADMIN,
  editor: USER_ROLES.MEMBER,
  reader: USER_ROLES.VIEWER,
};

export function getPermissionsForUserRole(role: string): Permission[] {
  return USER_ROLE_PERMISSIONS[role as UserRole] || [];
}

export function getPermissionsForAgentRole(role: string): Permission[] {
  return AGENT_ROLE_PERMISSIONS[role as AgentRole] || [];
}

export function computePermissionsFromRoles(
  userRoles: string[],
  agentRoles: string[] = []
): Permission[] {
  const permissions = new Set<Permission>();

  for (const role of userRoles) {
    for (const perm of getPermissionsForUserRole(role)) {
      permissions.add(perm);
    }
  }

  for (const role of agentRoles) {
    for (const perm of getPermissionsForAgentRole(role)) {
      permissions.add(perm);
    }
  }

  return Array.from(permissions);
}

export function isValidUserRole(role: string): role is UserRole {
  return Object.values(USER_ROLES).includes(role as UserRole);
}

export function isValidAgentRole(role: string): role is AgentRole {
  return Object.values(AGENT_ROLES).includes(role as AgentRole);
}

export function normalizeRole(role: string): UserRole | null {
  if (isValidUserRole(role)) return role;
  return LEGACY_ROLE_MAP[role] || null;
}

export function getRolesWithPermission(permission: Permission): UserRole[] {
  return (Object.entries(USER_ROLE_PERMISSIONS) as [UserRole, Permission[]][])
    .filter(([, perms]) => perms.includes(permission))
    .map(([role]) => role);
}

/**
 * Permission Types and Constants
 */

export const RESOURCES = {
  DASHBOARD: "dashboard",
  PROJECTS: "projects",
  TEAM: "team",
  SETTINGS: "settings",
  BILLING: "billing",
  ADMIN: "admin",
  USERS: "users",
  API_KEYS: "api_keys",
  INTEGRATIONS: "integrations",
  VALUE_TREES: "value_trees",
  COMMITMENTS: "commitments",
  AGENTS: "agents",
} as const;

export type Resource = (typeof RESOURCES)[keyof typeof RESOURCES];

export const ACTIONS = {
  VIEW: "view",
  CREATE: "create",
  EDIT: "edit",
  DELETE: "delete",
  MANAGE: "manage",
  INVITE: "invite",
  EXECUTE: "execute",
  ALL: "*",
} as const;

export type Action = (typeof ACTIONS)[keyof typeof ACTIONS];

export type Permission = `${Resource}:${Action}` | `${string}:${string}`;

export const PERMISSIONS = {
  DASHBOARD_VIEW: "dashboard:view" as Permission,

  PROJECTS_VIEW: "projects:view" as Permission,
  PROJECTS_CREATE: "projects:create" as Permission,
  PROJECTS_EDIT: "projects:edit" as Permission,
  PROJECTS_DELETE: "projects:delete" as Permission,

  TEAM_VIEW: "team:view" as Permission,
  TEAM_INVITE: "team:invite" as Permission,
  TEAM_MANAGE: "team:manage" as Permission,

  SETTINGS_VIEW: "settings:view" as Permission,
  SETTINGS_EDIT: "settings:edit" as Permission,

  BILLING_VIEW: "billing:view" as Permission,
  BILLING_MANAGE: "billing:manage" as Permission,

  USERS_VIEW: "users:view" as Permission,
  USERS_CREATE: "users:create" as Permission,
  USERS_EDIT: "users:edit" as Permission,
  USERS_DELETE: "users:delete" as Permission,

  API_KEYS_VIEW: "api_keys:view" as Permission,
  API_KEYS_CREATE: "api_keys:create" as Permission,
  API_KEYS_DELETE: "api_keys:delete" as Permission,

  INTEGRATIONS_VIEW: "integrations:view" as Permission,
  INTEGRATIONS_MANAGE: "integrations:manage" as Permission,

  ADMIN_ACCESS: "admin:view" as Permission,
  ADMIN_MANAGE: "admin:manage" as Permission,

  VALUE_TREES_VIEW: "value_trees:view" as Permission,
  VALUE_TREES_CREATE: "value_trees:create" as Permission,
  VALUE_TREES_EDIT: "value_trees:edit" as Permission,
  VALUE_TREES_DELETE: "value_trees:delete" as Permission,

  COMMITMENTS_VIEW: "commitments:view" as Permission,
  COMMITMENTS_CREATE: "commitments:create" as Permission,
  COMMITMENTS_EDIT: "commitments:edit" as Permission,

  AGENTS_VIEW: "agents:view" as Permission,
  AGENTS_CREATE: "agents:create" as Permission,
  AGENTS_EXECUTE: "agents:execute" as Permission,
} as const;

export function parsePermission(permission: string): { resource: string; action: string } | null {
  const parts = permission.split(":");
  if (parts.length !== 2 || !parts[0] || !parts[1]) return null;
  return { resource: parts[0], action: parts[1] };
}

export function createPermission(resource: string, action: string): Permission {
  return `${resource}:${action}` as Permission;
}

export function matchesPermission(granted: string, required: string): boolean {
  if (granted === required) return true;

  const grantedParts = parsePermission(granted);
  const requiredParts = parsePermission(required);

  if (!grantedParts || !requiredParts) return false;

  if (grantedParts.resource !== requiredParts.resource && grantedParts.resource !== "*") {
    return false;
  }

  if (grantedParts.action === "*") return true;

  return grantedParts.action === requiredParts.action;
}

export function expandWildcard(permission: Permission): Permission[] {
  const parsed = parsePermission(permission);
  if (!parsed) return [permission];

  if (parsed.action === "*") {
    return Object.values(ACTIONS)
      .filter(a => a !== "*")
      .map(a => createPermission(parsed.resource, a));
  }

  return [permission];
}

export function isValidPermission(permission: string): permission is Permission {
  const parsed = parsePermission(permission);
  if (!parsed) return false;
  return true;
}

export function hasPermission(userPermissions: string[] | undefined, required: Permission): boolean {
  if (!userPermissions?.length) return false;
  return userPermissions.some((granted) => matchesPermission(granted, required));
}

export function hasAllPermissions(userPermissions: string[] | undefined, required: Permission[]): boolean {
  if (!userPermissions?.length) return false;
  if (!required.length) return true;
  return required.every((r) => hasPermission(userPermissions, r));
}

export function hasAnyPermission(userPermissions: string[] | undefined, required: Permission[]): boolean {
  if (!userPermissions?.length) return false;
  if (!required.length) return true;
  return required.some((r) => hasPermission(userPermissions, r));
}

/**
 * PII Filter - Sanitize Sensitive Data from Logs
 *
 * SEC-004: CRITICAL - Prevents PII leakage in logs (GDPR/SOC 2 compliance)
 *
 * This filter removes or redacts sensitive information before logging.
 * NEVER log raw user objects, request bodies, or configuration.
 */

import { isDevelopment } from "../config/environment";

/**
 * Sensitive field patterns to redact
 */
const SENSITIVE_PATTERNS = [
  // Authentication & Security
  "password",
  "passwd",
  "pwd",
  "secret",
  "token",
  "api_key",
  "apikey",
  "api-key",
  "access_token",
  "refresh_token",
  "bearer",
  "authorization",
  "auth",
  "session",
  "cookie",
  "csrf",

  // Personal Information
  "email",
  "e-mail",
  "mail",
  "phone",
  "telephone",
  "mobile",
  "ssn",
  "social_security",
  "tax_id",
  "passport",
  "license",
  "drivers_license",

  // Financial
  "credit_card",
  "creditcard",
  "card_number",
  "cvv",
  "cvc",
  "expiry",
  "expiration",
  "bank_account",
  "routing_number",
  "iban",
  "swift",

  // Health
  "medical",
  "health",
  "diagnosis",
  "prescription",

  // Other Sensitive
  "ip_address",
  "ip",
  "mac_address",
  "geolocation",
  "location",
  "address",
  "dob",
  "date_of_birth",
  "birthdate",
];

/**
 * Check if a key contains sensitive information
 */
function isSensitiveKey(key: string): boolean {
  const lowerKey = key.toLowerCase();
  return SENSITIVE_PATTERNS.some((pattern) => lowerKey.includes(pattern.toLowerCase()));
}

/**
 * Check if a value looks like sensitive data
 */
function isSensitiveValue(value: unknown): boolean {
  if (typeof value !== "string") return false;

  // Check for JWT tokens
  if (/^eyJ[a-zA-Z0-9_-]+\.[a-zA-Z0-9_-]+\.[a-zA-Z0-9_-]+$/.test(value)) {
    return true;
  }

  // Check for API keys (long alphanumeric strings)
  if (/^[a-zA-Z0-9_-]{32,}$/.test(value)) {
    return true;
  }

  // Check for credit card numbers
  if (/^\d{13,19}$/.test(value.replace(/\s/g, ""))) {
    return true;
  }

  // Check for email addresses
  if (/^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(value)) {
    return true;
  }

  return false;
}

/**
 * Redact a sensitive value
 */
function redactValue(value: unknown, _key?: string): string {
  if (value === null || value === undefined) {
    return "[NULL]";
  }

  const valueStr = String(value);

  // In development, show partial value for debugging
  if (isDevelopment() && valueStr.length > 4) {
    return `[REDACTED:${valueStr.substring(0, 4)}...]`;
  }

  // In production, completely redact
  return "[REDACTED]";
}

/**
 * Sanitize an object for logging
 *
 * @param obj - Object to sanitize
 * @param maxDepth - Maximum recursion depth (prevents circular references)
 * @returns Sanitized object safe for logging
 */
export function sanitizeForLogging(obj: unknown, maxDepth: number = 5): unknown {
  // Handle primitives
  if (obj === null || obj === undefined) {
    return obj;
  }

  if (typeof obj !== "object") {
    // Check if primitive value is sensitive
    if (isSensitiveValue(obj)) {
      return redactValue(obj);
    }
    return obj;
  }

  // Prevent infinite recursion
  if (maxDepth <= 0) {
    return "[MAX_DEPTH_EXCEEDED]";
  }

  // Handle arrays
  if (Array.isArray(obj)) {
    return obj.map((item) => sanitizeForLogging(item, maxDepth - 1));
  }

  // Handle objects
  const sanitized: Record<string, unknown> = {};

  for (const [key, value] of Object.entries(obj)) {
    // Check if key is sensitive
    if (isSensitiveKey(key)) {
      sanitized[key] = redactValue(value, key);
      continue;
    }

    // Check if value is sensitive
    if (isSensitiveValue(value)) {
      sanitized[key] = redactValue(value, key);
      continue;
    }

    // Recursively sanitize nested objects
    if (typeof value === "object" && value !== null) {
      sanitized[key] = sanitizeForLogging(value, maxDepth - 1);
    } else {
      sanitized[key] = value;
    }
  }

  return sanitized;
}

/**
 * Sanitize user object for logging
 * Only log safe identifiers, never PII
 */
export function sanitizeUser(user: any): Record<string, unknown> {
  if (!user) return { user: null };

  return {
    id: user.id,
    role: user.role,
    tenant_id: user.tenant_id,
    // NEVER log: email, name, phone, address, etc.
  };
}

/**
 * Sanitize request object for logging
 * Only log safe metadata, never body or headers
 */
export function sanitizeRequest(req: any): Record<string, unknown> {
  if (!req) return { request: null };

  return {
    method: req.method,
    path: req.path || req.url,
    query: sanitizeForLogging(req.query),
    user_id: req.user?.id,
    tenant_id: req.tenantId ?? req.user?.tenant_id,
    ip: isDevelopment() ? req.ip : "[REDACTED]",
    // NEVER log: body, headers, cookies, authorization
  };
}

/**
 * Sanitize error objects for logging
 * Preserves stack trace in development only
 */
export function sanitizeError(error: unknown): Record<string, unknown> {
  if (!error) return { error: null };

  if (error instanceof Error) {
    // Get additional properties safely
    const additionalProps = sanitizeForLogging(
      Object.fromEntries(
        Object.entries(error).filter(([key]) => !["name", "message", "stack"].includes(key))
      )
    );

    return {
      name: error.name,
      message: error.message,
      stack: isDevelopment() ? error.stack : "[REDACTED]",
      // Only spread if it's an object
      ...(typeof additionalProps === "object" && additionalProps !== null ? additionalProps : {}),
    };
  }

  const sanitized = sanitizeForLogging(error);
  return typeof sanitized === "object" && sanitized !== null
    ? (sanitized as Record<string, unknown>)
    : { value: sanitized };
}

/**
 * Create a safe log context
 * Use this to build log context objects
 */
export function createLogContext(context: Record<string, unknown>): Record<string, unknown> {
  const sanitized = sanitizeForLogging(context);
  return typeof sanitized === "object" && sanitized !== null
    ? (sanitized as Record<string, unknown>)
    : { value: sanitized };
}

/**
 * Validate that a log message doesn't contain PII
 * Throws error in development if PII detected
 */
export function validateLogMessage(message: string, context?: unknown): void {
  if (!isDevelopment()) return;

  // Check message for email patterns
  if (/@[a-zA-Z0-9.-]+\.[a-zA-Z]{2,}/.test(message)) {
    console.warn("⚠️ WARNING: Possible email in log message:", message);
  }

  // Check context for sensitive keys
  if (context && typeof context === "object") {
    const keys = Object.keys(context);
    const sensitiveKeys = keys.filter(isSensitiveKey);

    if (sensitiveKeys.length > 0) {
      console.warn("⚠️ WARNING: Sensitive keys in log context:", sensitiveKeys);
    }
  }
}

/**
 * Example usage:
 *
 * // BAD:
 * logger.debug('User data:', user); // ❌ Logs PII
 *
 * // GOOD:
 * import { log } from './lib/logger';
 * import { sanitizeUser } from './lib/piiFilter';
 *
 * log.info('User action', sanitizeUser(user)); // ✅ Safe
 */

/**
 * Server Platform Utilities
 *
 * Server-specific utilities that require Node.js APIs.
 * This module should only be imported in server/Node.js contexts.
 *
 * @module @valueos/shared/platform/server
 */

/**
 * Check if code is running in a Node.js environment
 */
export function isServer(): boolean {
  return typeof process !== "undefined" && process.versions?.node !== undefined;
}

/**
 * Get an environment variable with optional default
 */
export function getEnv(key: string, defaultValue?: string): string | undefined {
  if (!isServer()) {
    return defaultValue;
  }

  return process.env[key] ?? defaultValue;
}

/**
 * Get a required environment variable, throws if missing
 */
export function requireEnv(key: string): string {
  if (!isServer()) {
    throw new Error(`Cannot access environment variables outside of server context`);
  }

  const value = process.env[key];
  if (!value) {
    throw new Error(`Missing required environment variable: ${key}`);
  }

  return value;
}

/**
 * Get the current working directory
 */
export function getCwd(): string {
  if (!isServer()) {
    return "/";
  }

  return process.cwd();
}

/**
 * Get the Node.js version
 */
export function getNodeVersion(): string {
  if (!isServer()) {
    return "unknown";
  }

  return process.versions.node;
}

/**
 * Check if running in production mode
 */
export function isProduction(): boolean {
  if (!isServer()) {
    return false;
  }

  return process.env.NODE_ENV === "production";
}

/**
 * Check if running in development mode
 */
export function isDevelopment(): boolean {
  if (!isServer()) {
    return false;
  }

  return process.env.NODE_ENV === "development" || !process.env.NODE_ENV;
}

/**
 * Check if running in test mode
 */
export function isTest(): boolean {
  if (!isServer()) {
    return false;
  }

  return process.env.NODE_ENV === "test" || process.env.VITEST === "true";
}

/**
 * Get memory usage in MB
 */
export function getMemoryUsage(): { heapUsed: number; heapTotal: number; rss: number } {
  if (!isServer()) {
    return { heapUsed: 0, heapTotal: 0, rss: 0 };
  }

  const usage = process.memoryUsage();
  return {
    heapUsed: Math.round(usage.heapUsed / 1024 / 1024),
    heapTotal: Math.round(usage.heapTotal / 1024 / 1024),
    rss: Math.round(usage.rss / 1024 / 1024),
  };
}

/**
 * Get process uptime in seconds
 */
export function getUptime(): number {
  if (!isServer()) {
    return 0;
  }

  return Math.round(process.uptime());
}

/**
 * Exit the process with a code
 */
export function exit(code: number = 0): never {
  if (!isServer()) {
    throw new Error("Cannot exit process outside of server context");
  }

  process.exit(code);
}

/**
 * Register a handler for uncaught exceptions
 */
export function onUncaughtException(handler: (error: Error) => void): void {
  if (!isServer()) {
    return;
  }

  process.on("uncaughtException", handler);
}

/**
 * Register a handler for unhandled promise rejections
 */
export function onUnhandledRejection(handler: (reason: unknown) => void): void {
  if (!isServer()) {
    return;
  }

  process.on("unhandledRejection", handler);
}

/**
 * Register a handler for process termination signals
 */
export function onShutdown(handler: () => void | Promise<void>): void {
  if (!isServer()) {
    return;
  }

  const signals: NodeJS.Signals[] = ["SIGTERM", "SIGINT", "SIGHUP"];

  for (const signal of signals) {
    process.on(signal, async () => {
      await handler();
      process.exit(0);
    });
  }
}

import { createClient, RedisClientType } from 'redis';
import { createLogger } from './logger';

const logger = createLogger({ component: 'redis-client' });

let client: RedisClientType | null = null;
let connecting: Promise<RedisClientType> | null = null;

export async function getRedisClient(): Promise<RedisClientType> {
  if (client?.isOpen) {
    return client;
  }

  if (!connecting) {
    client = createClient({
      url: process.env.REDIS_URL || 'redis://localhost:6379'
    });

    client.on('error', (err) => {
      logger.error('Redis client error', err);
      connecting = null;
    });

    connecting = client
      .connect()
      .then(() => {
        logger.info('Redis client connected');
        return client as RedisClientType;
      })
      .catch((error) => {
        logger.error('Failed to connect to Redis', error as Error);
        connecting = null;
        throw error;
      });
  }

  return connecting;
}

/**
 * Retry & Backoff Utilities
 *
 * Composable retry utilities with exponential backoff.
 * Returns Result types for consistent error handling.
 *
 * @example
 * const result = await withRetry(() => fetchData(), {
 *   maxAttempts: 3,
 *   baseDelayMs: 100,
 * });
 *
 * if (result.ok) {
 *   console.log(result.value);
 * } else {
 *   console.error('All retries failed:', result.error);
 * }
 */

import { Result, type AsyncResult } from '../types/result.js';

/**
 * Retry configuration options
 */
export interface RetryOptions {
  /** Maximum number of attempts (including initial) */
  maxAttempts: number;
  /** Base delay in milliseconds */
  baseDelayMs: number;
  /** Maximum delay in milliseconds */
  maxDelayMs: number;
  /** Backoff multiplier (e.g., 2 for exponential) */
  backoffMultiplier: number;
  /** Jitter factor (0-1) to randomize delay */
  jitterFactor: number;
  /** Predicate to determine if error is retryable */
  retryOn?: (error: unknown) => boolean;
  /** Callback for each retry attempt */
  onRetry?: (attempt: number, error: unknown, delayMs: number) => void;
}

/**
 * Default retry options
 */
export const DEFAULT_RETRY_OPTIONS: RetryOptions = {
  maxAttempts: 3,
  baseDelayMs: 100,
  maxDelayMs: 10000,
  backoffMultiplier: 2,
  jitterFactor: 0.1,
};

/**
 * Calculate delay with exponential backoff and jitter
 */
function calculateDelay(
  attempt: number,
  options: RetryOptions
): number {
  const exponentialDelay =
    options.baseDelayMs * Math.pow(options.backoffMultiplier, attempt - 1);
  const cappedDelay = Math.min(exponentialDelay, options.maxDelayMs);

  // Add jitter
  const jitter = cappedDelay * options.jitterFactor * (Math.random() * 2 - 1);
  return Math.max(0, Math.round(cappedDelay + jitter));
}

/**
 * Sleep for a specified duration
 */
function sleep(ms: number): Promise<void> {
  return new Promise((resolve) => setTimeout(resolve, ms));
}

/**
 * Default retry predicate - retry on any error
 */
const defaultRetryOn = (): boolean => true;

/**
 * Common retry predicates
 */
export const retryPredicates = {
  /** Retry on any error */
  always: () => true,

  /** Never retry */
  never: () => false,

  /** Retry on network errors */
  networkErrors: (error: unknown): boolean => {
    if (error instanceof Error) {
      const message = error.message.toLowerCase();
      return (
        message.includes('network') ||
        message.includes('timeout') ||
        message.includes('econnrefused') ||
        message.includes('econnreset') ||
        message.includes('fetch failed')
      );
    }
    return false;
  },

  /** Retry on specific HTTP status codes */
  httpStatus: (codes: number[]) => (error: unknown): boolean => {
    if (error && typeof error === 'object' && 'status' in error) {
      return codes.includes((error as { status: number }).status);
    }
    return false;
  },

  /** Retry on 5xx errors */
  serverErrors: (error: unknown): boolean => {
    if (error && typeof error === 'object' && 'status' in error) {
      const status = (error as { status: number }).status;
      return status >= 500 && status < 600;
    }
    return false;
  },

  /** Retry on rate limiting (429) */
  rateLimited: (error: unknown): boolean => {
    if (error && typeof error === 'object' && 'status' in error) {
      return (error as { status: number }).status === 429;
    }
    return false;
  },
};

/**
 * Execute an async function with retry logic
 */
export async function withRetry<T>(
  fn: () => Promise<T>,
  options?: Partial<RetryOptions>
): AsyncResult<T, Error> {
  const opts: RetryOptions = { ...DEFAULT_RETRY_OPTIONS, ...options };
  const retryOn = opts.retryOn ?? defaultRetryOn;

  let lastError: Error | undefined;

  for (let attempt = 1; attempt <= opts.maxAttempts; attempt++) {
    try {
      const result = await fn();
      return Result.ok(result);
    } catch (e) {
      lastError = e instanceof Error ? e : new Error(String(e));

      const isLastAttempt = attempt === opts.maxAttempts;
      const shouldRetry = !isLastAttempt && retryOn(e);

      if (!shouldRetry) {
        break;
      }

      const delayMs = calculateDelay(attempt, opts);

      if (opts.onRetry) {
        opts.onRetry(attempt, lastError, delayMs);
      }

      await sleep(delayMs);
    }
  }

  return Result.err(lastError ?? new Error('Retry failed'));
}

/**
 * Create a retryable version of an async function
 */
export function withRetryWrapper<T extends (...args: any[]) => Promise<any>>(
  fn: T,
  options?: Partial<RetryOptions>
): (...args: Parameters<T>) => AsyncResult<Awaited<ReturnType<T>>, Error> {
  return async (...args: Parameters<T>) => {
    return withRetry(() => fn(...args), options);
  };
}

/**
 * Execute with timeout
 */
export async function withTimeout<T>(
  fn: () => Promise<T>,
  timeoutMs: number
): AsyncResult<T, Error> {
  return new Promise((resolve) => {
    const timeoutId = setTimeout(() => {
      resolve(Result.err(new Error(`Operation timed out after ${timeoutMs}ms`)));
    }, timeoutMs);

    fn()
      .then((value) => {
        clearTimeout(timeoutId);
        resolve(Result.ok(value));
      })
      .catch((e) => {
        clearTimeout(timeoutId);
        resolve(Result.err(e instanceof Error ? e : new Error(String(e))));
      });
  });
}

/**
 * Execute with both retry and timeout
 */
export async function withRetryAndTimeout<T>(
  fn: () => Promise<T>,
  options?: Partial<RetryOptions> & { timeoutMs?: number }
): AsyncResult<T, Error> {
  const { timeoutMs = 30000, ...retryOptions } = options ?? {};

  return withRetry(
    () => {
      return new Promise<T>((resolve, reject) => {
        const timeoutId = setTimeout(() => {
          reject(new Error(`Operation timed out after ${timeoutMs}ms`));
        }, timeoutMs);

        fn()
          .then((value) => {
            clearTimeout(timeoutId);
            resolve(value);
          })
          .catch((e) => {
            clearTimeout(timeoutId);
            reject(e);
          });
      });
    },
    retryOptions
  );
}

/**
 * Circuit breaker state
 */
export interface CircuitBreakerState {
  failures: number;
  lastFailure: number | null;
  state: 'closed' | 'open' | 'half-open';
}

/**
 * Simple circuit breaker implementation
 */
export function createCircuitBreaker<T>(
  fn: () => Promise<T>,
  options: {
    failureThreshold: number;
    resetTimeoutMs: number;
    onStateChange?: (state: CircuitBreakerState['state']) => void;
  }
) {
  const state: CircuitBreakerState = {
    failures: 0,
    lastFailure: null,
    state: 'closed',
  };

  return async (): AsyncResult<T, Error> => {
    const now = Date.now();

    // Check if circuit should transition from open to half-open
    if (
      state.state === 'open' &&
      state.lastFailure &&
      now - state.lastFailure >= options.resetTimeoutMs
    ) {
      state.state = 'half-open';
      options.onStateChange?.('half-open');
    }

    // Reject immediately if circuit is open
    if (state.state === 'open') {
      return Result.err(new Error('Circuit breaker is open'));
    }

    try {
      const result = await fn();

      // Reset on success
      if (state.state === 'half-open') {
        state.state = 'closed';
        options.onStateChange?.('closed');
      }
      state.failures = 0;

      return Result.ok(result);
    } catch (e) {
      state.failures++;
      state.lastFailure = now;

      if (state.failures >= options.failureThreshold) {
        state.state = 'open';
        options.onStateChange?.('open');
      }

      return Result.err(e instanceof Error ? e : new Error(String(e)));
    }
  };
}

