import { createClient, type SupabaseClientOptions } from "@supabase/supabase-js";
import { getEnvVar, getSupabaseConfig } from "./env";
import { withRetry, retryPredicates } from "./retry";

// Custom fetch with retry logic for network stability
const fetchWithRetry = async (
  input: RequestInfo | URL,
  init?: RequestInit
): Promise<Response> => {
  const result = await withRetry(() => fetch(input, init), {
    retryOn: (error) =>
      retryPredicates.networkErrors(error) ||
      retryPredicates.serverErrors(error),
    maxAttempts: 3,
    baseDelayMs: 500,
  });

  if (result.ok) {
    return result.value;
  }
  throw result.error;
};

// Client-side configuration - only uses anon key
const supabaseConfig = getSupabaseConfig();
const supabaseUrl = supabaseConfig.url;
const supabaseAnonKey = supabaseConfig.anonKey;
const supabaseServiceRoleKey = supabaseConfig.serviceRoleKey;
const nodeEnv = getEnvVar("NODE_ENV") || getEnvVar("VITE_APP_ENV");
const allowInsecureAnonServerClient =
  getEnvVar("ALLOW_INSECURE_ANON_SERVER_CLIENT") === "true";
const isServer = typeof window === "undefined";
const isProduction = nodeEnv === "production";

if (isServer && isProduction && !supabaseServiceRoleKey) {
  throw new Error("SUPABASE_SERVICE_ROLE_KEY is required in production");
}

// Validate required client-side configuration
let supabase: any = null;
if (supabaseUrl && supabaseAnonKey) {
  const supabaseOptions: SupabaseClientOptions<"public"> = {
    db: {
      schema: "public",
    },
    auth: {
      autoRefreshToken: true,
      persistSession: false, // We handle persistence manually via SecureTokenManager for rotation support
      detectSessionInUrl: true,
    },
    global: {
      fetch: fetchWithRetry,
    },
  };

  // Client-side Supabase client - safe for browser
  supabase = createClient(supabaseUrl, supabaseAnonKey, supabaseOptions);
} else {
  console.warn(
    "Supabase client configuration is missing. Billing features will be disabled."
  );
}

export { supabase };

export function getSupabaseClient() {
  if (!supabase) {
    throw new Error(
      "Supabase client not configured. Billing features are disabled."
    );
  }
  return supabase;
}

function parseBearerToken(header?: string | string[]): string | null {
  if (!header) return null;
  const headerValue = Array.isArray(header) ? header[0] : header;
  if (!headerValue) return null;
  const prefix = "Bearer ";
  if (!headerValue.startsWith(prefix)) return null;
  const token = headerValue.slice(prefix.length).trim();
  return token.length > 0 ? token : null;
}

export function createRequestSupabaseClient(req: {
  headers?: { authorization?: string | string[] };
  supabase?: any;
  supabaseUser?: any;
  user?: any;
}) {
  if (!isServer) {
    throw new Error("Request-scoped Supabase client can only be used server-side");
  }

  if (!supabaseUrl || !supabaseAnonKey) {
    throw new Error("Supabase client not configured for request-scoped access");
  }

  const token = parseBearerToken(req.headers?.authorization);
  if (!token) {
    throw new Error("Authorization bearer token required for request-scoped Supabase client");
  }

  const requestOptions: SupabaseClientOptions<"public"> = {
    db: {
      schema: "public",
    },
    auth: {
      autoRefreshToken: false,
      persistSession: false,
      detectSessionInUrl: false,
    },
    global: {
      headers: {
        Authorization: `Bearer ${token}`,
      },
      fetch: fetchWithRetry,
    },
  };

  const client = createClient(supabaseUrl, supabaseAnonKey, requestOptions);
  (req as any).supabase = client;
  (req as any).supabaseUser = (req as any).user ?? null;
  return client;
}

export function getRequestSupabaseClient(req: {
  headers?: { authorization?: string | string[] };
  supabase?: any;
  supabaseUser?: any;
  user?: any;
}) {
  return (req as any).supabase ?? createRequestSupabaseClient(req);
}

// Server-side Supabase client - for backend services only
// This should NEVER be used in client-side code
export function createServerSupabaseClient(serviceKey?: string) {
  const serverKey = serviceKey || supabaseServiceRoleKey;

  if (!serverKey) {
    if (isProduction || !allowInsecureAnonServerClient) {
      throw new Error("Supabase service role key is required for server-side operations");
    }

    if (!supabaseAnonKey) {
      throw new Error("Supabase anon key missing for insecure server client fallback");
    }
  }

  if (typeof window !== "undefined") {
    throw new Error(
      "Server Supabase client cannot be used in browser environment"
    );
  }

  if (!supabaseUrl) {
    throw new Error("Supabase URL is required for server-side operations");
  }

  const serverOptions: SupabaseClientOptions<"public"> = {
    db: {
      schema: "public",
    },
    auth: {
      autoRefreshToken: false, // Server-side doesn't need auto-refresh
    },
    global: {
      fetch: fetchWithRetry,
    },
  };

  const resolvedKey = serverKey ?? supabaseAnonKey!;
  return createClient(supabaseUrl, resolvedKey, serverOptions);
}

/**
 * Tenant Verification Module
 *
 * SECURITY CRITICAL: Prevents cross-tenant data access
 *
 * This module provides functions to verify that users belong to the tenants
 * they are trying to access. All data access operations MUST verify tenant
 * membership to prevent unauthorized cross-tenant access.
 */

import { logger } from "./logger";

/**
 * Verify user belongs to tenant
 *
 * SECURITY CRITICAL: This function prevents cross-tenant data access.
 * It MUST be called before allowing any tenant-scoped data access.
 *
 * @param userId - User ID to verify
 * @param tenantId - Tenant ID (organization ID) to verify against
 * @returns Promise<boolean> - true if user belongs to tenant, false otherwise
 *
 * @example
 * ```typescript
 * const belongsToTenant = await verifyTenantMembership(userId, tenantId);
 * if (!belongsToTenant) {
 *   throw new SecurityError('Cross-tenant access denied');
 * }
 * ```
 */
export async function verifyTenantMembership(userId: string, tenantId: string): Promise<boolean> {
  try {
    // Import supabase client dynamically to avoid circular dependencies
    const { supabase } = await import("./supabase");

    const { data: membership, error: membershipError } = await supabase
      .from("user_tenants")
      .select("tenant_id, status")
      .eq("user_id", userId)
      .eq("tenant_id", tenantId)
      .maybeSingle();

    if (!membershipError && membership) {
      const membershipStatus = membership.status || "active";
      const belongsToTenant = membershipStatus === "active";

      if (!belongsToTenant) {
        logger.warn("Tenant membership inactive", {
          userId: maskUserId(userId),
          tenantId,
          status: membershipStatus,
        });
      }

      return belongsToTenant;
    }

    if (membershipError) {
      logger.warn("Tenant membership lookup failed, falling back to legacy org check", {
        userId: maskUserId(userId),
        tenantId,
        errorCode: membershipError.code,
      });
    }

    // Legacy fallback: single-tenant users table
    const { data, error } = await supabase
      .from("users")
      .select("organization_id")
      .eq("id", userId)
      .single();

    if (error || !data) {
      logger.error("Failed to verify tenant membership via legacy org check", error, {
        userId: maskUserId(userId),
        tenantId,
      });
      return false; // Fail closed - deny access on error
    }

    const belongsToTenant = data.organization_id === tenantId;

    if (!belongsToTenant) {
      logger.warn("Cross-tenant access attempt detected", {
        userId: maskUserId(userId),
        userTenant: data.organization_id,
        requestedTenant: tenantId,
        severity: "HIGH",
        securityEvent: "CROSS_TENANT_ACCESS_ATTEMPT",
      });
    }

    return belongsToTenant;
  } catch (error) {
    logger.error(
      "Tenant membership verification error",
      error instanceof Error ? error : undefined,
      {
        userId: maskUserId(userId),
        tenantId,
      }
    );
    return false; // Fail closed on any error
  }
}

/**
 * Verify user belongs to multiple tenants (batch operation)
 *
 * @param userId - User ID to verify
 * @param tenantIds - Array of tenant IDs to verify against
 * @returns Promise<Map<string, boolean>> - Map of tenantId to membership status
 */
export async function verifyTenantMembershipBatch(
  userId: string,
  tenantIds: string[]
): Promise<Map<string, boolean>> {
  const results = new Map<string, boolean>();

  try {
    const { supabase } = await import("./supabase");

    const { data: memberships, error: membershipsError } = await supabase
      .from("user_tenants")
      .select("tenant_id, status")
      .eq("user_id", userId)
      .eq("status", "active");

    if (!membershipsError && memberships) {
      const allowed = new Set(
        memberships.map((membership: { tenant_id: string }) => membership.tenant_id)
      );
      tenantIds.forEach((tenantId) => results.set(tenantId, allowed.has(tenantId)));
      return results;
    }

    if (membershipsError) {
      logger.warn("Batch tenant lookup failed, falling back to legacy org check", {
        userId: maskUserId(userId),
        errorCode: membershipsError.code,
      });
    }

    const { data, error } = await supabase
      .from("users")
      .select("organization_id")
      .eq("id", userId)
      .single();

    if (error || !data) {
      tenantIds.forEach((tenantId) => results.set(tenantId, false));
      return results;
    }

    const userTenantId = data.organization_id;

    tenantIds.forEach((tenantId) => {
      results.set(tenantId, tenantId === userTenantId);
    });

    return results;
  } catch (error) {
    logger.error("Batch tenant verification error", error instanceof Error ? error : undefined, {
      userId: maskUserId(userId),
      tenantCount: tenantIds.length,
    });

    // Fail closed - deny all on error
    tenantIds.forEach((tenantId) => results.set(tenantId, false));
    return results;
  }
}

/**
 * Get user's tenant ID (organization ID)
 *
 * @param userId - User ID
 * @returns Promise<string | null> - Tenant ID or null if not found
 */
export async function getUserTenantId(userId: string): Promise<string | null> {
  try {
    const { supabase } = await import("./supabase");

    const { data: membership, error: membershipError } = await supabase
      .from("user_tenants")
      .select("tenant_id, created_at, status")
      .eq("user_id", userId)
      .eq("status", "active")
      .order("created_at", { ascending: true })
      .limit(1)
      .maybeSingle();

    if (!membershipError && membership?.tenant_id) {
      return membership.tenant_id;
    }

    if (membershipError) {
      logger.warn("Tenant lookup failed, falling back to legacy org check", {
        userId: maskUserId(userId),
        error: membershipError.message,
      });
    }

    const { data, error } = await supabase
      .from("users")
      .select("organization_id")
      .eq("id", userId)
      .single();

    if (error || !data) {
      logger.warn("Failed to get user tenant ID", {
        userId: maskUserId(userId),
        error: error?.message,
      });
      return null;
    }

    return data.organization_id;
  } catch (error) {
    logger.error("Error getting user tenant ID", error instanceof Error ? error : undefined, {
      userId: maskUserId(userId),
    });
    return null;
  }
}

/**
 * Verify tenant exists and is active
 *
 * @param tenantId - Tenant ID to verify
 * @returns Promise<boolean> - true if tenant exists and is active
 */
export async function verifyTenantExists(tenantId: string): Promise<boolean> {
  try {
    const { supabase } = await import("./supabase");

    const { data: tenant, error: tenantError } = await supabase
      .from("tenants")
      .select("id, status")
      .eq("id", tenantId)
      .single();

    if (!tenantError && tenant) {
      return tenant.status === "active";
    }

    if (tenantError) {
      logger.warn("Tenant lookup failed, falling back to organizations table", {
        tenantId,
        errorCode: tenantError.code,
      });
    }

    const { data, error } = await supabase
      .from("organizations")
      .select("id, status")
      .eq("id", tenantId)
      .single();

    if (error || !data) {
      return false;
    }

    return data.status === "active" || data.status === "trial";
  } catch (error) {
    logger.error("Error verifying tenant exists", error instanceof Error ? error : undefined, {
      tenantId,
    });
    return false;
  }
}

/**
 * Mask user ID for logging (privacy protection)
 *
 * @param userId - User ID to mask
 * @returns Masked user ID
 */
function maskUserId(userId: string): string {
  if (userId.length <= 8) {
    return "***";
  }
  return `${userId.substring(0, 4)}...${userId.substring(userId.length - 4)}`;
}

/**
 * Security error for tenant violations
 */
export class TenantSecurityError extends Error {
  constructor(
    message: string,
    public readonly userId: string,
    public readonly requestedTenantId: string,
    public readonly userTenantId?: string
  ) {
    super(message);
    this.name = "TenantSecurityError";
  }
}

/**
 * Assert user belongs to tenant (throws on failure)
 *
 * Use this in critical paths where tenant verification failure should
 * immediately halt execution.
 *
 * @param userId - User ID to verify
 * @param tenantId - Tenant ID to verify against
 * @throws TenantSecurityError if user doesn't belong to tenant
 */
export async function assertTenantMembership(userId: string, tenantId: string): Promise<void> {
  const belongsToTenant = await verifyTenantMembership(userId, tenantId);

  if (!belongsToTenant) {
    const userTenantId = await getUserTenantId(userId);

    throw new TenantSecurityError(
      `User ${maskUserId(userId)} does not belong to tenant ${tenantId}`,
      userId,
      tenantId,
      userTenantId || undefined
    );
  }
}

/**
 * Middleware helper: Extract and verify tenant from request
 *
 * @param userId - User ID from authenticated request
 * @param tenantIdFromRequest - Tenant ID from request (path, query, or body)
 * @returns Promise<boolean> - true if verified, false otherwise
 */
export async function verifyRequestTenant(
  userId: string,
  tenantIdFromRequest: string
): Promise<boolean> {
  // Verify tenant exists first
  const tenantExists = await verifyTenantExists(tenantIdFromRequest);
  if (!tenantExists) {
    logger.warn("Request for non-existent tenant", {
      userId: maskUserId(userId),
      tenantId: tenantIdFromRequest,
    });
    return false;
  }

  // Verify user belongs to tenant
  return verifyTenantMembership(userId, tenantIdFromRequest);
}

/**
 * Validation Utilities
 *
 * Composable validation helpers built on Zod schemas.
 * Returns Result types for consistent error handling.
 *
 * @example
 * const result = validate(UserSchema, data);
 * if (result.ok) {
 *   console.log(result.value.email);
 * } else {
 *   console.error(result.error.issues);
 * }
 */

import { z, type ZodSchema, type ZodError } from 'zod';
import { Result, type AsyncResult } from '../types/result.js';

/**
 * Validation error with structured details
 */
export interface ValidationError {
  code: 'VALIDATION_ERROR';
  message: string;
  issues: ValidationIssue[];
}

export interface ValidationIssue {
  path: (string | number)[];
  message: string;
  code: string;
}

/**
 * Convert ZodError to ValidationError
 */
function toValidationError(error: ZodError): ValidationError {
  return {
    code: 'VALIDATION_ERROR',
    message: `Validation failed: ${error.issues.length} issue(s)`,
    issues: error.issues.map((issue) => ({
      path: issue.path,
      message: issue.message,
      code: issue.code,
    })),
  };
}

/**
 * Validate data against a Zod schema
 * Returns Result<T, ValidationError>
 */
export function validate<T>(
  schema: ZodSchema<T>,
  data: unknown
): Result<T, ValidationError> {
  const result = schema.safeParse(data);
  if (result.success) {
    return Result.ok(result.data);
  }
  return Result.err(toValidationError(result.error));
}

/**
 * Validate data asynchronously (for schemas with async refinements)
 */
export async function validateAsync<T>(
  schema: ZodSchema<T>,
  data: unknown
): AsyncResult<T, ValidationError> {
  const result = await schema.safeParseAsync(data);
  if (result.success) {
    return Result.ok(result.data);
  }
  return Result.err(toValidationError(result.error));
}

/**
 * Validate and return data or null (no error details)
 */
export function safeValidate<T>(schema: ZodSchema<T>, data: unknown): T | null {
  const result = schema.safeParse(data);
  return result.success ? result.data : null;
}

/**
 * Validate and throw on failure (for cases where you want exceptions)
 */
export function validateOrThrow<T>(schema: ZodSchema<T>, data: unknown): T {
  return schema.parse(data);
}

/**
 * Create a validator function from a schema
 */
export function createValidator<T>(schema: ZodSchema<T>) {
  return {
    validate: (data: unknown) => validate(schema, data),
    validateAsync: (data: unknown) => validateAsync(schema, data),
    safeValidate: (data: unknown) => safeValidate(schema, data),
    validateOrThrow: (data: unknown) => validateOrThrow(schema, data),
    isValid: (data: unknown): data is T => schema.safeParse(data).success,
  };
}

/**
 * Compose multiple validations
 */
export function validateAll<T extends Record<string, unknown>>(
  validations: { [K in keyof T]: Result<T[K], ValidationError> }
): Result<T, ValidationError> {
  const errors: ValidationIssue[] = [];
  const values: Partial<T> = {};

  for (const [key, result] of Object.entries(validations)) {
    if (result.ok) {
      values[key as keyof T] = result.value as T[keyof T];
    } else {
      errors.push(
        ...result.error.issues.map((issue: ValidationIssue) => ({
          ...issue,
          path: [key, ...issue.path],
        }))
      );
    }
  }

  if (errors.length > 0) {
    return Result.err({
      code: 'VALIDATION_ERROR',
      message: `Validation failed: ${errors.length} issue(s)`,
      issues: errors,
    });
  }

  return Result.ok(values as T);
}

/**
 * Common validation schemas
 */
export const commonSchemas = {
  /**
   * UUID v4 format
   */
  uuid: z.string().uuid(),

  /**
   * Prefixed ID format (e.g., "usr_abc123")
   */
  prefixedId: (prefix: string) =>
    z.string().regex(new RegExp(`^${prefix}_[a-zA-Z0-9_-]+$`), {
      message: `Invalid ${prefix} ID format`,
    }),

  /**
   * Email address
   */
  email: z.string().email(),

  /**
   * Non-empty string
   */
  nonEmpty: z.string().min(1, 'Cannot be empty'),

  /**
   * Positive integer
   */
  positiveInt: z.number().int().positive(),

  /**
   * ISO date string
   */
  isoDate: z.string().datetime(),

  /**
   * URL
   */
  url: z.string().url(),

  /**
   * Pagination params
   */
  pagination: z.object({
    page: z.number().int().positive().default(1),
    pageSize: z.number().int().positive().max(100).default(20),
  }),
};

/**
 * Type-safe schema inference helper
 */
export type Infer<T extends ZodSchema> = z.infer<T>;

/**
 * API validation schemas
 */

import { z } from "zod";

export const APIErrorSchema = z.object({
  code: z.string(),
  message: z.string(),
  details: z.record(z.unknown()).optional(),
});

export const APIMetaSchema = z.object({
  requestId: z.string(),
  timestamp: z.string(),
  duration: z.number().optional(),
});

export const APIResponseSchema = <T extends z.ZodTypeAny>(dataSchema: T) =>
  z.object({
    success: z.boolean(),
    data: dataSchema.optional(),
    error: APIErrorSchema.optional(),
    meta: APIMetaSchema.optional(),
  });

export const PaginationSchema = z.object({
