/**
 * Typed Domain Events
 *
 * Type-safe event contracts for cross-package communication.
 * Uses discriminated unions for exhaustive pattern matching.
 *
 * @example
 * function handleEvent(event: DomainEvent) {
 *   switch (event.type) {
 *     case 'user.created':
 *       console.log(event.payload.userId);
 *       break;
 *     case 'agent.task.completed':
 *       console.log(event.payload.result);
 *       break;
 *   }
 * }
 */

/**
 * Base event metadata included with all events
 */
export interface EventMeta {
  eventId: string;
  timestamp: string;
  source: string;
  correlationId?: string;
  causationId?: string;
}

/**
 * User domain events
 */
export type UserEvent =
  | {
      type: "user.created";
      payload: { userId: string; tenantId: string; email: string };
    }
  | {
      type: "user.updated";
      payload: { userId: string; changes: Record<string, unknown> };
    }
  | {
      type: "user.deleted";
      payload: { userId: string; tenantId: string };
    }
  | {
      type: "user.role.changed";
      payload: { userId: string; oldRole: string; newRole: string };
    };

/**
 * Tenant domain events
 */
export type TenantEvent =
  | {
      type: "tenant.created";
      payload: { tenantId: string; name: string; plan: string };
    }
  | {
      type: "tenant.plan.changed";
      payload: { tenantId: string; oldPlan: string; newPlan: string };
    }
  | {
      type: "tenant.suspended";
      payload: { tenantId: string; reason: string };
    };

/**
 * Agent domain events
 */
export type AgentEvent =
  | {
      type: "agent.task.started";
      payload: { agentId: string; taskId: string; taskType: string };
    }
  | {
      type: "agent.task.completed";
      payload: { agentId: string; taskId: string; result: unknown; durationMs: number };
    }
  | {
      type: "agent.task.failed";
      payload: { agentId: string; taskId: string; error: string };
    }
  | {
      type: "agent.tool.invoked";
      payload: { agentId: string; toolName: string; input: unknown };
    };

/**
 * Memory domain events
 */
export type MemoryEvent =
  | {
      type: "memory.stored";
      payload: { memoryId: string; type: string; vectorId?: string };
    }
  | {
      type: "memory.retrieved";
      payload: { memoryId: string; relevanceScore?: number };
    }
  | {
      type: "memory.deleted";
      payload: { memoryId: string };
    };

/**
 * System events
 */
export type SystemEvent =
  | {
      type: "system.health.degraded";
      payload: { service: string; reason: string };
    }
  | {
      type: "system.health.recovered";
      payload: { service: string };
    }
  | {
      type: "system.rate.limited";
      payload: { tenantId: string; resource: string; limit: number };
    };

/**
 * All domain events union
 */
export type DomainEvent = UserEvent | TenantEvent | AgentEvent | MemoryEvent | SystemEvent;

/**
 * Event with metadata wrapper
 */
export type EnvelopedEvent<T extends DomainEvent = DomainEvent> = T & {
  meta: EventMeta;
};

/**
 * Extract event type string
 */
export type EventType = DomainEvent["type"];

/**
 * Extract payload type for a specific event type
 */
export type EventPayload<T extends EventType> = Extract<DomainEvent, { type: T }>["payload"];

/**
 * Event handler type
 */
export type EventHandler<T extends EventType> = (
  payload: EventPayload<T>,
  meta: EventMeta
) => void | Promise<void>;

/**
 * Event registry for type-safe subscriptions
 */
export type EventHandlers = {
  [K in EventType]?: EventHandler<K>[];
};

/**
 * Helper to create typed events
 */
export function createEvent<T extends EventType>(
  type: T,
  payload: EventPayload<T>,
  meta: Partial<EventMeta> = {}
): EnvelopedEvent<Extract<DomainEvent, { type: T }>> {
  return {
    type,
    payload,
    meta: {
      eventId: crypto.randomUUID(),
      timestamp: new Date().toISOString(),
      source: "unknown",
      ...meta,
    },
  } as EnvelopedEvent<Extract<DomainEvent, { type: T }>>;
}

/**
 * Event topics for message bus routing
 */
export const EVENT_TOPICS = {
  SAGA_COMMANDS: "saga.commands",
  WORKFLOW_EVENTS: "workflow.events",
  AGENT_REQUESTS: "agent.requests",
  AGENT_RESPONSES: "agent.responses",
  DEAD_LETTER: "dead.letter",
} as const;

/**
 * Agent request event type
 */
export interface AgentRequestEvent {
  type: "agent.request";
  payload: {
    agentId: string;
    userId: string;
    sessionId: string;
    tenantId: string;
    query: string;
    context?: Record<string, unknown>;
    parameters?: Record<string, unknown>;
    priority: string;
    timeout: number;
  };
  meta: EventMeta;
}

/**
 * Helper to create base events
 */
export function createBaseEvent<T extends EventType>(
  type: T,
  payload: EventPayload<T>,
  meta: Partial<EventMeta> = {}
): EnvelopedEvent<Extract<DomainEvent, { type: T }>> {
  return createEvent(type, payload, meta);
}

/**
 * Result Type Pattern
 *
 * Standardized error handling across packages using a Result monad.
 * Eliminates null/undefined ambiguity and provides composable error handling.
 *
 * @example
 * const result = await fetchUser(id);
 * if (result.ok) {
 *   console.log(result.value.name);
 * } else {
 *   console.error(result.error.message);
 * }
 */

export type Result<T, E = Error> =
  | { ok: true; value: T }
  | { ok: false; error: E };

export type AsyncResult<T, E = Error> = Promise<Result<T, E>>;

/**
 * Result constructors and utilities
 */
export const Result = {
  /**
   * Create a successful result
   */
  ok<T>(value: T): Result<T, never> {
    return { ok: true, value };
  },

  /**
   * Create a failed result
   */
  err<E>(error: E): Result<never, E> {
    return { ok: false, error };
  },

  /**
   * Check if result is successful
   */
  isOk<T, E>(result: Result<T, E>): result is { ok: true; value: T } {
    return result.ok;
  },

  /**
   * Check if result is failed
   */
  isErr<T, E>(result: Result<T, E>): result is { ok: false; error: E } {
    return !result.ok;
  },

  /**
   * Map the success value
   */
  map<T, U, E>(result: Result<T, E>, fn: (value: T) => U): Result<U, E> {
    if (result.ok) {
      return Result.ok(fn(result.value));
    }
    return result;
  },

  /**
   * Map the error value
   */
  mapErr<T, E, F>(result: Result<T, E>, fn: (error: E) => F): Result<T, F> {
    if (!result.ok) {
      return Result.err(fn(result.error));
    }
    return result;
  },

  /**
   * Chain results (flatMap)
   */
  flatMap<T, U, E>(
    result: Result<T, E>,
    fn: (value: T) => Result<U, E>
  ): Result<U, E> {
    if (result.ok) {
      return fn(result.value);
    }
    return result;
  },

  /**
   * Unwrap the value or return a fallback
   */
  unwrapOr<T, E>(result: Result<T, E>, fallback: T): T {
    if (result.ok) {
      return result.value;
    }
    return fallback;
  },

  /**
   * Unwrap the value or compute a fallback from the error
   */
  unwrapOrElse<T, E>(result: Result<T, E>, fn: (error: E) => T): T {
    if (result.ok) {
      return result.value;
    }
    return fn(result.error);
  },

  /**
   * Unwrap the value or throw the error
   */
  unwrap<T, E>(result: Result<T, E>): T {
    if (result.ok) {
      return result.value;
    }
    throw result.error;
  },

  /**
   * Wrap a function that might throw into a Result
   */
  fromTry<T>(fn: () => T): Result<T, Error> {
    try {
      return Result.ok(fn());
    } catch (e) {
      return Result.err(e instanceof Error ? e : new Error(String(e)));
    }
  },

  /**
   * Wrap an async function that might throw into a Result
   */
  async fromTryAsync<T>(fn: () => Promise<T>): AsyncResult<T, Error> {
    try {
      return Result.ok(await fn());
    } catch (e) {
      return Result.err(e instanceof Error ? e : new Error(String(e)));
    }
  },

  /**
   * Combine multiple results into a single result
   * Returns the first error if any result is an error
   */
  all<T extends readonly Result<unknown, unknown>[]>(
    results: T
  ): Result<
    { [K in keyof T]: T[K] extends Result<infer U, unknown> ? U : never },
    T[number] extends Result<unknown, infer E> ? E : never
  > {
    const values: unknown[] = [];
    for (const result of results) {
      if (!result.ok) {
        return result as any;
      }
      values.push(result.value);
    }
    return Result.ok(values) as any;
  },

  /**
   * Match on success or failure with exhaustive pattern matching
   */
  match<T, E, U>(
    result: Result<T, E>,
    handlers: {
      ok: (value: T) => U;
      err: (error: E) => U;
    }
  ): U {
    if (result.ok) {
      return handlers.ok(result.value);
    }
    return handlers.err(result.error);
  },
};

/**
 * Type guard to narrow Result to success
 */
export function isOk<T, E>(result: Result<T, E>): result is { ok: true; value: T } {
  return result.ok;
}

/**
 * Type guard to narrow Result to failure
 */
export function isErr<T, E>(result: Result<T, E>): result is { ok: false; error: E } {
  return !result.ok;
}

/**
 * LoadingSkeleton Component
 * Provides consistent loading states to prevent layout shift
 */

import React from "react";
import { Skeleton } from "./skeleton";
import { cn } from "@/lib/utils";

interface LoadingSkeletonProps {
  className?: string;
  variant?: "default" | "card" | "text" | "button";
  lines?: number;
}

export function LoadingSkeleton({
  className,
  variant = "default",
  lines = 3,
}: LoadingSkeletonProps) {
  if (variant === "card") {
    return (
      <div className={cn("space-y-3", className)}>
        <Skeleton className="h-4 w-3/4" />
        <Skeleton className="h-4 w-1/2" />
        <Skeleton className="h-32 w-full" />
      </div>
    );
  }

  if (variant === "text") {
    return (
      <div className={cn("space-y-2", className)}>
        {Array.from({ length: lines }).map((_, i) => (
          <Skeleton key={i} className="h-4 w-full" />
        ))}
      </div>
    );
  }

  if (variant === "button") {
    return <Skeleton className={cn("h-10 w-24", className)} />;
  }

  return <Skeleton className={cn("h-4 w-full", className)} />;
}
